INSERT INTO snes_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 228, 'Super Mario World', 'SNES/Super Famicom', 3, 95174, 95174, 95174, 89, 0, '2D Platforming', NULL, 'Nintendo', '1990-11-21', 'Super Mario World is a platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released in Japan in 1990, in North America in 1991 and PAL territories in 1992. The player controls Mario on his quest to save Princess Peach and Dinosaur Land from the series'' antagonist Bowser and the Koopalings. The gameplay is similar to that of earlier Super Mario games; players control Mario through a series of levels in which the goal is to reach the goalpost at the end. Super Mario World introduces Yoshi, a ridable dinosaur who can eat enemies and spit some of them out as projectiles.', 'https://media.retroachievements.org/Images/112443.png', 'https://media.retroachievements.org/Images/109856.png', 'https://media.retroachievements.org/Images/110144.png', 'https://media.retroachievements.org/Images/110145.png', 5),
  (2, 355, 'The Legend of Zelda: A Link to the Past', 'SNES/Super Famicom', 3, 41287, 41287, 41287, 109, 0, 'Action-Adventure', NULL, 'Nintendo', '1991-11-21', 'The Legend of Zelda: A Link to the Past is a 1991 action-adventure game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third game in The Legend of Zelda series, following 1987''s Zelda II: The Adventure of Link, and is the first entry in the series to be released for the SNES.', 'https://media.retroachievements.org/Images/059119.png', 'https://media.retroachievements.org/Images/022504.png', 'https://media.retroachievements.org/Images/072051.png', 'https://media.retroachievements.org/Images/072052.png', 4.8),
  (3, 466, 'Donkey Kong Country 2: Diddy''s Kong Quest', 'SNES/Super Famicom', 3, 26782, 26782, 26782, 80, 0, '2D Platforming', 'Rare', 'Nintendo', '1995-11-21', 'Donkey Kong Country 2: Diddy''s Kong Quest  is a 1995 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on 21 November 1995 in Japan, 4 December in North America, and 14 December in Europe. It is the second installment of the Donkey Kong Country series and the sequel to Donkey Kong Country (1994).', 'https://media.retroachievements.org/Images/107029.png', 'https://media.retroachievements.org/Images/060825.png', 'https://media.retroachievements.org/Images/000162.png', 'https://media.retroachievements.org/Images/000163.png', 4.7),
  (4, 236, 'Super Metroid', 'SNES/Super Famicom', 3, 25802, 25802, 25802, 52, 0, 'Metroidvania', 'Intelligent Systems', 'Nintendo', '1994-03-19', 'Super Metroid is a 1994 action-adventure game developed by Nintendo and Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third Metroid game, following the Game Boy game Metroid II: Return of Samus (1991). The player controls bounty hunter Samus Aran, who travels to planet Zebes to retrieve an infant Metroid creature stolen by the Space Pirate leader Ridley.', 'https://media.retroachievements.org/Images/060989.png', 'https://media.retroachievements.org/Images/096236.png', 'https://media.retroachievements.org/Images/065700.png', 'https://media.retroachievements.org/Images/073825.png', 4.7),
  (5, 319, 'Chrono Trigger', 'SNES/Super Famicom', 3, 25040, 25040, 25040, 76, 0, 'Turn-Based RPG', 'Square', 'Squaresoft', '1995-03-11', 'Chrono Trigger is a 1995 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the first installment of the Chrono series. The game''s plot follows a group of adventurers who travel through time to prevent a global catastrophe.', 'https://media.retroachievements.org/Images/093950.png', 'https://media.retroachievements.org/Images/000222.png', 'https://media.retroachievements.org/Images/106517.png', 'https://media.retroachievements.org/Images/036180.png', 4.7),
  (6, 814, 'Kirby Super Star', 'SNES/Super Famicom', 3, 19509, 19509, 19509, 57, 0, '2D Platforming', 'HAL Laboratory', 'HAL Laboratory', '1996-03-21', 'Kirby Super Star, released as Kirby''s Fun Pak in PAL regions, is a 1996 anthology platform game developed by HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. It is part of the Kirby series of video games by HAL Laboratory. The game was advertised as a compilation featuring eight games: seven short subsections with the same basic gameplay, and two minigames.', 'https://media.retroachievements.org/Images/076409.png', 'https://media.retroachievements.org/Images/003681.png', 'https://media.retroachievements.org/Images/004908.png', 'https://media.retroachievements.org/Images/004909.png', 4.6),
  (7, 637, 'Mega Man X', 'SNES/Super Famicom', 3, 19407, 19407, 19407, 57, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-12-17', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/043274.png', 'https://media.retroachievements.org/Images/015026.png', 'https://media.retroachievements.org/Images/035379.png', 'https://media.retroachievements.org/Images/035387.png', 4.6),
  (8, 558, 'Super Mario World 2: Yoshi''s Island', 'SNES/Super Famicom', 3, 18799, 18799, 18799, 63, 0, '2D Platforming', NULL, 'Nintendo', '1995-08-05', 'Super Mario World 2: Yoshi''s Island is a 1995 platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The player controls Yoshi dinosaurs on their quest to reunite baby Mario with his brother Luigi, who has been kidnapped by the wizard Kamek. Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items with Mario''s help.', 'https://media.retroachievements.org/Images/061087.png', 'https://media.retroachievements.org/Images/112063.png', 'https://media.retroachievements.org/Images/038811.png', 'https://media.retroachievements.org/Images/038813.png', 4.6),
  (9, 232, 'Super Mario Kart', 'SNES/Super Famicom', 3, 18229, 18229, 18229, 47, 0, 'Kart Racing', NULL, 'Nintendo', '1992-08-27', 'Super Mario Kart is a 1992 kart racing game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The first game in the Mario Kart series, it was released in Japan on August 27, 1992, North America on September 1, 1992, the United Kingdom in October 1992, and Europe on January 21, 1993. Selling 8.76 million copies worldwide, the game went on to become the fourth best-selling SNES game of all time. Super Mario Kart was re-released on the Wii''s Virtual Console in 2009, on the Wii U''s Virtual Console in 2013, and on the New Nintendo 3DS''s Virtual Console in 2016. Nintendo re-released Super Mario Kart in 2017 as part of the company''s Super NES Classic Edition.', 'https://media.retroachievements.org/Images/069326.png', 'https://media.retroachievements.org/Images/053513.png', 'https://media.retroachievements.org/Images/070108.png', 'https://media.retroachievements.org/Images/000726.png', 4.6),
  (10, 471, 'Super Mario RPG: Legend of the Seven Stars', 'SNES/Super Famicom', 3, 16769, 16769, 16769, 100, 0, 'Turn-Based RPG', 'Square', 'Nintendo', '1996-03-09', 'Super Mario RPG: Legend of the Seven Stars is a 1996 role-playing video game developed by Square and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was the final Mario game for the SNES, and was directed by Chihiro Fujioka and Yoshihiko Maekawa, produced by Shigeru Miyamoto, and scored by Yoko Shimomura.', 'https://media.retroachievements.org/Images/085860.png', 'https://media.retroachievements.org/Images/026395.png', 'https://media.retroachievements.org/Images/001537.png', 'https://media.retroachievements.org/Images/001538.png', 4.6),
  (11, 350, 'Teenage Mutant Ninja Turtles IV: Turtles in Time', 'SNES/Super Famicom', 3, 15931, 15931, 15931, 30, 0, 'Beat ''em Up', 'Konami', 'Konami', '1992-07-24', 'Teenage Mutant Ninja Turtles: Turtles in Time, released as Teenage Mutant Hero Turtles: Turtles in Time in Europe, is a 1991 beat ''em up game developed and published by Konami for arcades. A sequel to the original Teenage Mutant Ninja Turtles arcade game, it is a side-scrolling game based mainly on the 1987 TMNT animated series. Originally an arcade game, Turtles in Time was ported to the Super Nintendo Entertainment System in 1992 under the title Teenage Mutant Ninja Turtles IV: Turtles in Time, continuing the numbering from the earlier Turtles games released on the original NES. That same year, a game that borrowed many elements, Teenage Mutant Ninja Turtles: The Hyperstone Heist, was released for the Sega Genesis.', 'https://media.retroachievements.org/Images/044532.png', 'https://media.retroachievements.org/Images/120293.png', 'https://media.retroachievements.org/Images/035357.png', 'https://media.retroachievements.org/Images/053029.png', 4.6),
  (12, 264, 'EarthBound', 'SNES/Super Famicom', 3, 15391, 15391, 15391, 105, 0, 'Turn-Based RPG', 'APE | Creatures, HAL Laboratory, Pax Softnica', 'Nintendo', '1994-08-27', 'EarthBound, originally released in Japan as Mother 2: Gīgu no Gyakushū, is a 1994 role-playing video game developed by Ape Inc. and HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. The second entry in the Mother series, it follows a young boy named Ness and his party of Paula, Jeff and Poo, as they travel the world to collect melodies from eight Sanctuaries in order to defeat the universal cosmic destroyer Giygas.', 'https://media.retroachievements.org/Images/100662.png', 'https://media.retroachievements.org/Images/001836.png', 'https://media.retroachievements.org/Images/002470.png', 'https://media.retroachievements.org/Images/002471.png', 4.6),
  (13, 379, 'Aladdin', 'SNES/Super Famicom', 3, 14302, 14302, 14302, 40, 0, '2D Platforming', 'Capcom', 'Capcom', '1993-11-26', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/096482.png', 'https://media.retroachievements.org/Images/096400.png', 'https://media.retroachievements.org/Images/000102.png', 'https://media.retroachievements.org/Images/000103.png', 4.6),
  (14, 473, 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!', 'SNES/Super Famicom', 3, 13200, 13200, 13200, 84, 0, '2D Platforming', 'Rare', 'Nintendo', '1996-01-01', 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!  is a 1996 platform Collectathon developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third installment of the Donkey Kong Country series, and serves as a sequel to 1995''s Donkey Kong Country 2: Diddy''s Kong Quest. It was also re-released for the Game Boy Advance (GBA) in 2005. The game was made available to download on the Wii''s Virtual Console service in 2007, as well as for the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/107030.png', 'https://media.retroachievements.org/Images/060826.png', 'https://media.retroachievements.org/Images/000139.png', 'https://media.retroachievements.org/Images/000140.png', 4.6),
  (15, 562, 'Super Castlevania IV', 'SNES/Super Famicom', 3, 12880, 12880, 12880, 36, 0, '2D Platforming', 'Konami', 'Konami', '1991-10-31', 'Super Castlevania IV is a 1991 platform game developed and published by Konami for the Super Nintendo Entertainment System. It has been re-released multiple times, including for the Super NES Classic Edition.', 'https://media.retroachievements.org/Images/072972.png', 'https://media.retroachievements.org/Images/072401.png', 'https://media.retroachievements.org/Images/000986.png', 'https://media.retroachievements.org/Images/034865.png', 4.6),
  (16, 539, 'Super Punch-Out!!', 'SNES/Super Famicom', 3, 12767, 12767, 12767, 74, 0, 'Sports - Boxing', 'Nintendo', 'Nintendo', '1994-10-24', 'Super Punch-Out!! is a boxing video game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). It was released on October 24, 1994 in North America and again in the same region in 1996. It was released in the United Kingdom on February 10, 1995 for the same console and in Japan in 1998 for the Super Famicom through the Nintendo Power flash RAM cartridge series. The game is also included in the GameCube version of Fight Night Round 2 as an extra game due to the inclusion of Little Mac in the game. The game was released for the Wii''s Virtual Console in Europe on March 20, 2009, in North America on March 30, 2009, and in Japan on July 7, 2009. The game was also released on the New Nintendo 3DS eShop on May 5, 2016. Nintendo re-released Super Punch-Out!! in the United States in September 2017 as part of the company''s Super NES Classic Edition. It is the fourth game in the Punch-Out!! series, taking place after the Punch-Out!! game for the Nintendo Entertainment System (NES).', 'https://media.retroachievements.org/Images/112176.png', 'https://media.retroachievements.org/Images/060910.png', 'https://media.retroachievements.org/Images/050219.png', 'https://media.retroachievements.org/Images/050220.png', 4.6),
  (17, 648, 'Street Fighter II Turbo: Hyper Fighting', 'SNES/Super Famicom', 3, 11003, 11003, 11003, 32, 0, '2D Fighting', 'Capcom', 'Capcom', '1993-07-11', 'Street Fighter II Turbo: Hyper Fighting, released as Street Fighter II Dash Turbo in Japan, is a 1992 fighting game developed and published by Capcom for arcades. It is the third arcade version of Street Fighter II, part of the Street Fighter franchise, following Street Fighter II: Champion Edition, and was initially released as an enhancement kit for that game. Released less than a year after the previous installment, Hyper Fighting introduced a faster playing speed and new special moves for certain characters, as well as further refinement to the character balance.', 'https://media.retroachievements.org/Images/117039.png', 'https://media.retroachievements.org/Images/044318.png', 'https://media.retroachievements.org/Images/044319.png', 'https://media.retroachievements.org/Images/000907.png', 4.5),
  (18, 405, 'Zombies Ate My Neighbors', 'SNES/Super Famicom', 3, 10897, 10897, 10897, 95, 0, 'Action', 'LucasArts | Lucasfilm', 'Konami', '1993-09-01', 'Zombies Ate My Neighbors is a 1993 run and gun video game developed by LucasArts and published by Konami for the Super Nintendo Entertainment System and Sega Genesis. The player controls the protagonists Zeke and Julie in order to rescue the titular neighbors from monsters often seen in horror films. Aiding them in this task are a variety of weapons and power-ups that can be used to battle the numerous enemies in each level. Various elements and aspects of horror movies are referenced in the game with some of its more violent content being censored in various territories such as Europe and Australia, where it is known only as Zombies.', 'https://media.retroachievements.org/Images/043812.png', 'https://media.retroachievements.org/Images/074446.png', 'https://media.retroachievements.org/Images/074447.png', 'https://media.retroachievements.org/Images/074448.png', 4.5),
  (19, 470, 'Super Bomberman', 'SNES/Super Famicom', 3, 10760, 10760, 10760, 54, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1993-04-28', 'Super Bomberman is a 1993 action maze video game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. Part of the Bomberman series, it is the first game in the to retain the Bomberman title in Europe, instead of being renamed to Dynablaster or Eric and the Floaters.', 'https://media.retroachievements.org/Images/043551.png', 'https://media.retroachievements.org/Images/112595.png', 'https://media.retroachievements.org/Images/039426.png', 'https://media.retroachievements.org/Images/039427.png', 4.5),
  (20, 400, 'Secret of Mana', 'SNES/Super Famicom', 3, 10560, 10560, 10560, 85, 0, 'Action RPG', 'Square', 'Squaresoft', '1993-08-06', 'Secret of Mana, originally released in Japan as Seiken Densetsu 2, is a 1993 action role-playing game developed and published by Square for the Super Nintendo Entertainment System. It is the sequel to the 1991 game Seiken Densetsu which was released in North America as Final Fantasy Adventure and in Europe as Mystic Quest. Secret of Mana was the first Seiken Densetsu title to be marketed as part of the Mana series rather than the Final Fantasy series. Set in a high fantasy universe, the game follows three heroes as they attempt to prevent an empire from conquering the world with the power of an ancient flying fortress.', 'https://media.retroachievements.org/Images/099440.png', 'https://media.retroachievements.org/Images/067832.png', 'https://media.retroachievements.org/Images/000277.png', 'https://media.retroachievements.org/Images/000152.png', 4.5),
  (21, 813, 'Kirby''s Dream Land 3', 'SNES/Super Famicom', 3, 10462, 10462, 10462, 32, 0, '2D Platforming', 'HAL Laboratory', 'Nintendo', '1997-11-17', 'Kirby''s Dream Land 3 is a 1997 platform game developed by HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. Starring Kirby, it is the fifth installment in the Kirby series and the third game under the Kirby''s Dream Land name. Although the first game was largely unrelated, Dream Land 3 features many similar characters to Dream Land 2. Dream Land 3 was followed by Kirby 64: The Crystal Shards in 2000.', 'https://media.retroachievements.org/Images/114700.png', 'https://media.retroachievements.org/Images/055863.png', 'https://media.retroachievements.org/Images/118726.png', 'https://media.retroachievements.org/Images/118727.png', 4.5),
  (22, 238, 'Goof Troop', 'SNES/Super Famicom', 3, 8682, 8682, 8682, 28, 0, NULL, 'Capcom', 'Capcom', '1993-07-11', 'Goof-Troop is an American animated sitcom produced by Walt Disney Television Animation. The series focuses on the relationship between single-father Goofy and his son, Max, as well as their neighbor Pete and his family. Created by Robert Taylor and Michael Peraza Jr., the main-series of 65 episodes aired in first-run-syndication from 1992 to 1993 on The Disney Afternoon programming block, while an additional thirteen episodes aired on Saturday mornings on ABC. A Christmas special was also produced and aired in syndication in late 1992.', 'https://media.retroachievements.org/Images/111712.png', 'https://media.retroachievements.org/Images/000371.png', 'https://media.retroachievements.org/Images/034926.png', 'https://media.retroachievements.org/Images/000369.png', 4.5),
  (23, 344, 'Contra III: The Alien Wars', 'SNES/Super Famicom', 3, 8596, 8596, 8596, 30, 0, '2D Platforming, Run & Gun', 'Konami', 'Konami', '1992-02-28', 'Contra III: The Alien Wars is a 1992 run and gun video game developed and published by Konami for the Super Nintendo Entertainment System (SNES). It is the third home console entry in the Contra series after Contra (1988) and Super Contra (1990) for the Nintendo Entertainment System (NES). In PAL regions, it was retitled Super Probotector: Alien Rebels and the player characters were replaced with robots. The player is tasked with fighting off an alien invasion of Earth across six stages. Four stages feature side-scrolling action traditional to the series while two are presented from an overhead perspective. It is the first Contra title to have been directed by Nobuya Nakazato who later directed other games in the series. He designed Contra III to feature more comical elements, a more cinematic soundtrack, and tighter stage design than its predecessors.', 'https://media.retroachievements.org/Images/110814.png', 'https://media.retroachievements.org/Images/000144.png', 'https://media.retroachievements.org/Images/038814.png', 'https://media.retroachievements.org/Images/068064.png', 4.5),
  (24, 889, 'Earthworm Jim', 'SNES/Super Famicom', 3, 8213, 8213, 8213, 35, 0, '2D Platforming', 'Shiny Entertainment', 'Virgin Interactive', '1994-10-01', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/115156.png', 'https://media.retroachievements.org/Images/005599.png', 'https://media.retroachievements.org/Images/005597.png', 'https://media.retroachievements.org/Images/005598.png', 4.5),
  (25, 469, 'Mega Man 7', 'SNES/Super Famicom', 3, 7710, 7710, 7710, 49, 0, '2D Platforming', 'Capcom', 'Capcom', '1995-03-24', 'Mega Man 7, known in Japan as Rockman 7: Showdown of Destiny!, is a 1995 action game developed and published by Capcom for the Super Nintendo Entertainment System (SNES). It is the seventh game in the original Mega Man series. The game was released in Japan on March 24, 1995 and was localized later in the year in North America and Europe.', 'https://media.retroachievements.org/Images/105305.png', 'https://media.retroachievements.org/Images/000919.png', 'https://media.retroachievements.org/Images/035629.png', 'https://media.retroachievements.org/Images/035631.png', 4.4),
  (26, 629, 'Mega Man X2', 'SNES/Super Famicom', 3, 7681, 7681, 7681, 70, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-12-16', 'Mega Man X2, known as Rockman X2 (ロックマンX2) in Japan, is a 1994 platform game developed and published by Capcom for the Super Nintendo Entertainment System (SNES). The game was released in Japan on December 16, 1994, and in North America and PAL regions in 1995. It is the direct sequel to Mega Man X, released one year prior. Mega Man X2 takes place in the near future in which humans try to peacefully coexist with intelligent robots called Reploids, with some of the Reploids going Maverick and threatening daily life. The plot follows the android protagonist X, a Maverick Hunter who saved humanity from the evil Sigma six months earlier. A trio of Mavericks calling themselves the X-Hunters has arisen, intent on destroying X by luring him with body parts of his comrade Zero, who died in the conflict with Sigma''s right-hand robot Vile.', 'https://media.retroachievements.org/Images/023582.png', 'https://media.retroachievements.org/Images/000929.png', 'https://media.retroachievements.org/Images/035388.png', 'https://media.retroachievements.org/Images/035380.png', 4.4),
  (27, 333, 'Sunset Riders', 'SNES/Super Famicom', 3, 7654, 7654, 7654, 36, 0, NULL, 'Konami', 'Konami', '1993-08-06', 'Sunset Riders is a 1991 run and gun video game developed and published by Konami for arcades. It was released in North America in October 1991 and Japan in November 1991. It is set in the American Old West, where the player(s) take control of bounty hunters who are seeking the rewards offered for various criminals.', 'https://media.retroachievements.org/Images/052084.png', 'https://media.retroachievements.org/Images/032880.png', 'https://media.retroachievements.org/Images/035384.png', 'https://media.retroachievements.org/Images/032886.png', 4.4),
  (28, 341, 'Final Fantasy VI', 'SNES/Super Famicom', 3, 7629, 7629, 7629, 115, 0, NULL, 'Square', 'Squaresoft', '1994-10-20', 'Final Fantasy VI, titled Final Fantasy III in its initial North American release, is a 1994 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the sixth main entry in the Final Fantasy series, the final to feature 2D sprite based graphics, and the first to be directed by someone other than series creator Hironobu Sakaguchi; the role was instead filled by Yoshinori Kitase and Hiroyuki Ito. Long-time collaborator Yoshitaka Amano returned as character designer and concept artist, while composer Nobuo Uematsu returned to compose the game''s score, which has been released on several soundtrack albums.', 'https://media.retroachievements.org/Images/070796.png', 'https://media.retroachievements.org/Images/001377.png', 'https://media.retroachievements.org/Images/001378.png', 'https://media.retroachievements.org/Images/034210.png', 4.4),
  (29, 323, 'Final Fight 3', 'SNES/Super Famicom', 3, 7474, 7474, 7474, 59, 0, NULL, 'Capcom', 'Capcom', '1995-12-22', 'Final Fight 3, released in Japan as Final Fight Tough , is a 1995 beat ''em up video game developed and published by Capcom for the Super Nintendo Entertainment System. It is the second sequel to Final Fight released for the Super NES, following Final Fight 2. Like its predecessor, it was produced by Capcom''s consumer division with no preceding arcade version released.', 'https://media.retroachievements.org/Images/101605.png', 'https://media.retroachievements.org/Images/006039.png', 'https://media.retroachievements.org/Images/036002.png', 'https://media.retroachievements.org/Images/036004.png', 4.4),
  (30, 392, 'Arkanoid: Doh It Again', 'SNES/Super Famicom', 3, 7215, 7215, 7215, 61, 0, 'Brick Breakers', 'Taito', 'Taito', '1997-01-15', 'Arkanoid: Doh It Again is a 1997 block breaker video game developed and published by Taito. It was first released in Japan for the Super Famicom and Windows, while Nintendo published the SNES version in Australia, North America and Europe. It is the third installment in the Arkanoid series after the original 1986 arcade game and its sequel Arkanoid: Revenge of Doh.', 'https://media.retroachievements.org/Images/008000.png', 'https://media.retroachievements.org/Images/007188.png', 'https://media.retroachievements.org/Images/007998.png', 'https://media.retroachievements.org/Images/007999.png', 4.4),
  (31, 270, 'ActRaiser', 'SNES/Super Famicom', 3, 6648, 6648, 6648, 66, 0, 'Action', 'Quintet', 'Enix, Squaresoft', '1990-12-16', 'ActRaiser is a 1990 video game developed by Quintet and published by Enix for the Super Nintendo Entertainment System. It combines traditional side-scrolling platforming and sections with city building elements. A sequel, ActRaiser 2, was released for the Super NES in 1993. In 2007, ActRaiser became available on the Wii''s Virtual Console download service in Europe, North America, and Japan. A version of the game was also released for European mobile phones in 2004. A remake, Actraiser Renaissance, was released for several platforms in 2021.', 'https://media.retroachievements.org/Images/110040.png', 'https://media.retroachievements.org/Images/001235.png', 'https://media.retroachievements.org/Images/004107.png', 'https://media.retroachievements.org/Images/028692.png', 4.4),
  (32, 1192, 'Street Fighter II: The World Warrior', 'SNES/Super Famicom', 3, 6170, 6170, 6170, 31, 0, '2D Fighting', 'Capcom', 'Capcom', '1991-02-06', 'Street Fighter II: The World Warrior is a 1991 fighting game developed and published by Capcom for arcades. It is the second installment in the Street Fighter series, and the sequel to 1987''s Street Fighter. Designed by Yoshiki Okamoto and Akira Yasuda, who had previously worked on the game Final Fight, it is the fourteenth game to use Capcom''s CP System arcade system board. Street Fighter II vastly improved many of the concepts introduced in the first game, including the use of special command-based moves, a combo system, a six-button configuration, and a wider selection of playable characters, each with a unique fighting style.', 'https://media.retroachievements.org/Images/117038.png', 'https://media.retroachievements.org/Images/006020.png', 'https://media.retroachievements.org/Images/006018.png', 'https://media.retroachievements.org/Images/006019.png', 4.4),
  (33, 1103, 'Pocky & Rocky', 'SNES/Super Famicom', 3, 6084, 6084, 6084, 36, 0, NULL, 'Natsume', 'Natsume', '1992-12-22', 'Pocky & Rocky, known in Japan as Kiki Kaikai , is a scrolling shooter video game series originating with the 1986 arcade game Kiki Kaikai by Taito. The game was adapted into a series of home console games mainly developed and published by Natsume which were titled Pocky & Rocky in the West. The games follow the adventures of a young Shinto shrine maiden, Pocky, and her tanuki companion, Rocky, as they fight against monsters from Japanese mythology.', 'https://media.retroachievements.org/Images/026005.png', 'https://media.retroachievements.org/Images/061348.png', 'https://media.retroachievements.org/Images/085738.png', 'https://media.retroachievements.org/Images/085739.png', 4.4),
  (34, 401, 'Super Star Wars', 'SNES/Super Famicom', 3, 5896, 5896, 5896, 31, 0, '2D Platforming', 'LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '1992-06-01', 'Super Star Wars is a 1992 run and gun video game based on the 1977 film Star Wars, developed by LucasArts and Sculptured Software and published by JVC Musical Industries for the Super Nintendo Entertainment System. The game features side-scrolling run and gun and platform gameplay, although it has stages which feature other challenges, such as driving a landspeeder or piloting an X-wing. It also features multiple playable characters with different abilities.', 'https://media.retroachievements.org/Images/072974.png', 'https://media.retroachievements.org/Images/005978.png', 'https://media.retroachievements.org/Images/005977.png', 'https://media.retroachievements.org/Images/005980.png', 4.4),
  (35, 300, 'Castlevania: Dracula X', 'SNES/Super Famicom', 3, 5814, 5814, 5814, 30, 0, NULL, 'Konami', 'Konami', '1995-07-21', 'Castlevania: Dracula X, titled Castlevania: Vampire''s Kiss in Europe and Akumajou Dracula XX in Japan, is a 1995 platform game developed and published by Konami for the Super Nintendo Entertainment System. It is the second Castlevania installment to be released for the Super NES. It is a remake of Castlevania: Rondo of Blood, which was previously released in Japan on the PC Engine Super CD-ROM2 in 1993. While the plot is similar to Rondo of Blood and it uses many of that game''s graphics, it features new levels and altered gameplay elements, rather than being a direct port because of the limits of the Super NES cartridge format and exclusivity agreements with PC Engine maker NEC. It was released on July 21, 1995 in Japan, in September 1995 in North America, February 22, 1996 in Europe, and on June 22, 1996, in Australia. The game received mixed reviews, with journalists considering it inferior to Rondo of Blood and criticizing its high difficulty.', 'https://media.retroachievements.org/Images/106341.png', 'https://media.retroachievements.org/Images/071788.png', 'https://media.retroachievements.org/Images/071787.png', 'https://media.retroachievements.org/Images/071786.png', 4.4),
  (36, 1216, 'Super Ghouls ''n Ghosts', 'SNES/Super Famicom', 3, 5797, 5797, 5797, 50, 0, '2D Platforming, Action', 'Capcom', 'Capcom', '1991-10-04', 'Super Ghouls ''n Ghosts, known as Chō Makaimura in Japan, is a 1991 platform video game developed and published by Capcom for the Super Nintendo Entertainment System. The third installment in the Ghosts ''n Goblins series and the first not to be released for arcades, it again depicts knight Arthur saving Princess Guinevere and the kingdom from Emperor Sardius, who has cast a spell that has revived the Ghoul Realm.', 'https://media.retroachievements.org/Images/119128.png', 'https://media.retroachievements.org/Images/000136.png', 'https://media.retroachievements.org/Images/000015.png', 'https://media.retroachievements.org/Images/000016.png', 4.4),
  (37, 582, 'Ultimate Mortal Kombat 3', 'SNES/Super Famicom', 3, 5742, 5742, 5742, 45, 0, '2D Fighting', 'Avalanche Software', 'Acclaim, Williams Entertainment', '1996-10-01', 'Ultimate Mortal Kombat 3 is a 1995 fighting game developed and published by Midway for arcades. Part of the Mortal Kombat series, it is a standalone update of 1995''s earlier Mortal Kombat 3 with an altered gameplay system and some new features, as well as additional characters like the returning favorites Reptile, Kitana, Jade and Scorpion, who were missing from Mortal Kombat 3.', 'https://media.retroachievements.org/Images/054585.png', 'https://media.retroachievements.org/Images/006697.png', 'https://media.retroachievements.org/Images/001355.png', 'https://media.retroachievements.org/Images/001356.png', 4.4),
  (38, 887, 'E.V.O.: Search for Eden', 'SNES/Super Famicom', 3, 5726, 5726, 5726, 59, 0, 'Action RPG', 'Almanic | Givro', 'Enix', '1993-01-01', 'E.V.O.: Search for Eden is a 1992 action-adventure game developed by Almanic Corporation and published by Enix for the Super NES. Combining traditional platforming mechanics with experience and leveling mechanics originating from role playing games, E.V.O.: Search for Eden involves the player navigating a creature through a number of side-scrolling levels while undergoing bodily evolution to cope with ever-changing environments. It is heavily based on Almanic''s original title, 46 Okunen Monogatari ~The Shinka Ron~, released in Japan in 1990 for the PC-9801.', 'https://media.retroachievements.org/Images/061403.png', 'https://media.retroachievements.org/Images/004293.png', 'https://media.retroachievements.org/Images/004294.png', 'https://media.retroachievements.org/Images/004295.png', 4.4),
  (39, 1034, 'Mighty Morphin Power Rangers', 'SNES/Super Famicom', 3, 5649, 5649, 5649, 21, 0, 'Beat ''em Up', 'Natsume', 'Bandai', '1994-09-01', 'Mighty Morphin Power Rangers (MMPR) is an American superhero television series produced by Saban Entertainment, which aired from August 28, 1993 to November 27, 1995, on the Fox Kids programming block, lasting three seasons. The series drew elements and stock footage from Super Sentai, a Japanese television series by Toei Company. Each season was inspired by Kyoryu Sentai Zyuranger, Gosei Sentai Dairanger, and Ninja Sentai Kakuranger, respectively. The series is the first entry of the Power Rangers franchise.', 'https://media.retroachievements.org/Images/103846.png', 'https://media.retroachievements.org/Images/001906.png', 'https://media.retroachievements.org/Images/035632.png', 'https://media.retroachievements.org/Images/035633.png', 4.4),
  (40, 468, 'Final Fight 2', 'SNES/Super Famicom', 3, 5583, 5583, 5583, 45, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1993-01-01', 'Final Fight 2  is a 1993 beat ''em up game released by Capcom for the Super Nintendo Entertainment System. It is the direct sequel to the 1989 arcade game Final Fight, which was previously also released for the SNES. Final Fight 2 was developed by Capcom''s consumer division with no preceding coin-op version. The game was re-released onto Wii''s Virtual Console service in 2009 worldwide.', 'https://media.retroachievements.org/Images/101604.png', 'https://media.retroachievements.org/Images/125189.png', 'https://media.retroachievements.org/Images/001260.png', 'https://media.retroachievements.org/Images/028603.png', 4.4),
  (41, 878, 'The Lion King', 'SNES/Super Famicom', 3, 5461, 5461, 5461, 33, 0, '2D Platforming', 'Westwood Studios | Westwood Associates', 'Virgin Interactive', '1994-12-08', 'The Lion King is a 1994 American animated musical drama film directed by Roger Allers and Rob Minkoff, produced by Don Hahn, and written by Irene Mecchi, Jonathan Roberts, and Linda Woolverton. It was produced by Walt Disney Feature Animation, and features an ensemble voice cast consisting of Matthew Broderick, James Earl Jones, Jeremy Irons, Jonathan Taylor Thomas, Moira Kelly, Niketa Calame, Nathan Lane, Ernie Sabella, Whoopi Goldberg, Cheech Marin, Rowan Atkinson, and Robert Guillaume. The story follows a young lion prince named Simba, who is exiled from his kingdom after his father Mufasa is murdered by his uncle Scar to seize the throne. As he grows up, Simba must decide whether to return home to confront Scar and reclaim his place as king.', 'https://media.retroachievements.org/Images/034930.png', 'https://media.retroachievements.org/Images/003100.png', 'https://media.retroachievements.org/Images/003101.png', 'https://media.retroachievements.org/Images/003102.png', 4.4),
  (42, 351, 'Star Fox', 'SNES/Super Famicom', 3, 5312, 5312, 5312, 39, 0, 'Rail Shooter', 'Argonaut Games', 'Nintendo', '1993-02-21', 'Star Fox is a rail shooter, space flight simulator, and third person action-adventure video game series created by the Japanese game designer Shigeru Miyamoto and developed and published by Nintendo. The games follow the Star Fox combat team of anthropomorphic animals, led by chief protagonist Fox McCloud. Gameplay involves missions around the Lylat planetary system in the futuristic Arwing fighter spacecraft, in other vehicles, and on foot. The original Star Fox (1993) is a forward-scrolling 3D rail shooter, but later games add more directional freedom.', 'https://media.retroachievements.org/Images/071849.png', 'https://media.retroachievements.org/Images/001342.png', 'https://media.retroachievements.org/Images/088715.png', 'https://media.retroachievements.org/Images/001340.png', 4.4),
  (43, 815, 'Tetris Attack', 'SNES/Super Famicom', 3, 5302, 5302, 5302, 50, 0, NULL, 'Intelligent Systems', 'Nintendo', '1995-10-27', 'Tetris Attack, also known as Panel de Pon in Japan, is a 1995 puzzle video game developed by Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System. A Game Boy version was released a year later. In the game, the player must arrange matching colored blocks in vertical or horizontal rows to clear them. The blocks steadily rise to the top of the playfield, with new blocks being added at the bottom. Several gameplay modes are present, including a time attack and multiplayer mode.', 'https://media.retroachievements.org/Images/112288.png', 'https://media.retroachievements.org/Images/000166.png', 'https://media.retroachievements.org/Images/000165.png', 'https://media.retroachievements.org/Images/000034.png', 4.4),
  (44, 945, 'Illusion of Gaia', 'SNES/Super Famicom', 3, 5020, 5020, 5020, 45, 0, 'Action RPG', 'Quintet', 'Enix', '1993-11-27', 'Illusion of Gaia, known in PAL territories as Illusion of Time, is an action role-playing video game developed by Quintet for the Super Nintendo Entertainment System. The game was released in Japan by Enix in 1993, and in North America and PAL territories by Nintendo in 1994 and 1995. Set in a fantasy reimagining of Earth, the game''s plot centers on a boy named Will who is chosen to save the world from an impending disaster. Throughout the game, the player guides Will through levels inspired by the ancient ruins of real-world civilizations and Wonders of the World, including the Great Pyramid and the Great Wall of China.', 'https://media.retroachievements.org/Images/063183.png', 'https://media.retroachievements.org/Images/066745.png', 'https://media.retroachievements.org/Images/004212.png', 'https://media.retroachievements.org/Images/004215.png', 4.3),
  (45, 237, 'Rock n'' Roll Racing', 'SNES/Super Famicom', 3, 4890, 4890, 4890, 35, 0, 'Racing', 'Blizzard Entertainment', 'Interplay Entertainment', '1993-04-06', 'Rock n'' Roll Racing is a vehicular combat-based racing video game developed by Silicon & Synapse and published by Interplay Productions for the Super Nintendo Entertainment System in 1993 and the Mega Drive/Genesis in 1994. The game prominently features a number of popular heavy metal and rock songs in its soundtrack, hence the game''s title. After Silicon & Synapse rebranded into Blizzard Entertainment, a port to the Game Boy Advance was released in 2003. In celebration of the company''s 30th anniversary, a new version titled Definitive Edition alongside emulated re-releases of the original game were re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/045856.png', 'https://media.retroachievements.org/Images/000870.png', 'https://media.retroachievements.org/Images/000869.png', 'https://media.retroachievements.org/Images/000119.png', 4.3),
  (46, 1374, 'Super Bomberman 4', 'SNES/Super Famicom', 3, 4800, 4800, 4800, 37, 0, 'Action', 'Produce!', 'Hudson Soft', '1996-04-26', 'Super Bomberman 4 is an action-party video game developed by Produce and published by Hudson Soft. It was developed for the Super Famicom, released on April 26, 1996, in Japan. Part of the Bomberman franchise, it is the fourth installment of the Super Bomberman series.', 'https://media.retroachievements.org/Images/043554.png', 'https://media.retroachievements.org/Images/038288.png', 'https://media.retroachievements.org/Images/001488.png', 'https://media.retroachievements.org/Images/034094.png', 4.3),
  (47, 1233, 'Super Smash T.V.', 'SNES/Super Famicom', 3, 4783, 4783, 4783, 21, 0, 'Twin Stick Shooter', 'Beam Software', 'Acclaim', '1992-01-01', 'Smash TV is a 1990 twin-stick shooter video game developed and published by Williams Electronics for arcades. It was designed by Eugene Jarvis and programmed by Mark Turmell, with similar gameplay to Jarvis'' earlier game Robotron: 2084 (1982). The Super Nintendo Entertainment System, Sega Genesis, Master System and Game Gear versions are titled Super Smash TV.', 'https://media.retroachievements.org/Images/072194.png', 'https://media.retroachievements.org/Images/002088.png', 'https://media.retroachievements.org/Images/002090.png', 'https://media.retroachievements.org/Images/002091.png', 4.3),
  (48, 1168, 'Soul Blazer', 'SNES/Super Famicom', 3, 4704, 4704, 4704, 80, 0, 'Action RPG', 'Quintet', 'Enix', '1992-01-31', 'Soul Blazer, released in Japan as Soul Blader, is an action role-playing video game developed by Quintet and published by Enix for the Super Nintendo Entertainment System. It was released in 1992 in Japan and North America, but not released in Europe until 1994. It was not released in the United Kingdom.', 'https://media.retroachievements.org/Images/035099.png', 'https://media.retroachievements.org/Images/052164.png', 'https://media.retroachievements.org/Images/005449.png', 'https://media.retroachievements.org/Images/005450.png', 4.3),
  (49, 242, 'Terranigma', 'SNES/Super Famicom', 3, 4569, 4569, 4569, 98, 0, 'Action RPG', 'Quintet', 'Enix', '1995-10-20', 'Terranigma is a 1995 action role-playing game developed by Quintet for the Super Nintendo Entertainment System (SNES), with manga artist Kamui Fujiwara acting as the character designer. The game tells the story of the Earth''s resurrection by the hands of a boy named Ark, and its progress from the evolution of life to the present day. The game is the third entry in an unofficial trilogy of action role-playing games created by Quintet, also including Soul Blazer (1992) and Illusion of Gaia (1993).', 'https://media.retroachievements.org/Images/035303.png', 'https://media.retroachievements.org/Images/028323.png', 'https://media.retroachievements.org/Images/002917.png', 'https://media.retroachievements.org/Images/002920.png', 4.3),
  (50, 830, 'The Adventures of Batman & Robin', 'SNES/Super Famicom', 3, 4500, 4500, 4500, 27, 0, 'Action', 'Konami', 'Konami', '1994-01-01', 'Batman: The Animated Series is an American animated superhero television series based on the DC Comics superhero Batman. Developed by Bruce Timm and Eric Radomski, and produced by Warner Bros. Animation, it originally aired on Fox Kids from September 5, 1992, to September 15, 1995, with a total of 85 episodes. Mid-way through the series'' run, it was re-titled The Adventures of Batman & Robin.', 'https://media.retroachievements.org/Images/048996.png', 'https://media.retroachievements.org/Images/005796.png', 'https://media.retroachievements.org/Images/035402.png', 'https://media.retroachievements.org/Images/035403.png', 4.3),
  (51, 436, 'Blackthorne', 'SNES/Super Famicom', 3, 4390, 4390, 4390, 26, 0, 'Action-Adventure', 'Blizzard Entertainment', 'Interplay Entertainment', '1994-01-01', 'Blackthorne is a cinematic platform game developed by Blizzard Entertainment. It was released for the Super NES and MS-DOS in 1994. The cover art for the SNES version was drawn by Jim Lee. The following year, Blackthorne was released for the Sega 32X with additional content. In 2013, Blizzard released the game for free on their Battle.net PC client. In celebration of the company''s 30th anniversary, Blackthorne was re-released for Nintendo Switch, PlayStation 4, Windows, and Xbox One as part of the Blizzard Arcade Collection in February 2021.', 'https://media.retroachievements.org/Images/045841.png', 'https://media.retroachievements.org/Images/004631.png', 'https://media.retroachievements.org/Images/030906.png', 'https://media.retroachievements.org/Images/030905.png', 4.3),
  (52, 2132, 'Doom', 'SNES/Super Famicom', 3, 4322, 4322, 4322, 57, 0, 'First-Person Shooter', 'Sculptured Software | Iguana West', 'Williams Entertainment', '1995-09-01', 'Doom is an American media franchise created by John Carmack, John Romero, Adrian Carmack, Kevin Cloud, and Tom Hall. The series usually focuses on the exploits of an unnamed space marine operating under the auspices of the Union Aerospace Corporation (UAC), who fights hordes of demons and the undead to save Earth from an apocalyptic invasion.', 'https://media.retroachievements.org/Images/076913.png', 'https://media.retroachievements.org/Images/077372.png', 'https://media.retroachievements.org/Images/007274.png', 'https://media.retroachievements.org/Images/007275.png', 4.3),
  (53, 340, 'Wild Guns', 'SNES/Super Famicom', 3, 4217, 4217, 4217, 87, 0, 'Gallery Shooter', 'Natsume', 'Natsume', '1994-08-12', 'Wild Guns is a 1994 shooting gallery video game developed and published by Natsume Co., Ltd. for the Super Nintendo Entertainment System. Set in the Wild West with steampunk and sci-fi influences, the story follows Annie and her bounty hunter Clint, seeking revenge for the death of her family. The player controls either Annie or Clint sidestepping and jumping in the foreground while shooting down enemy robots in the background and dodging enemy bullets. These gameplay mechanics combine elements from third-person shooters and light gun games.', 'https://media.retroachievements.org/Images/071911.png', 'https://media.retroachievements.org/Images/000911.png', 'https://media.retroachievements.org/Images/035393.png', 'https://media.retroachievements.org/Images/035394.png', 4.3),
  (54, 500, 'Super Bomberman 2', 'SNES/Super Famicom', 3, 4070, 4070, 4070, 63, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1994-04-28', 'Super Bomberman 2 is a 1994 action maze video game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. It is the second installment of the Super Bomberman series, part of the larger Bomberman franchise, and the only installment without a two-player story mode. The game was re-released in 2026 as part of the Super Bomberman Collection compilation.', 'https://media.retroachievements.org/Images/043552.png', 'https://media.retroachievements.org/Images/112599.png', 'https://media.retroachievements.org/Images/015551.png', 'https://media.retroachievements.org/Images/015552.png', 4.3),
  (55, 821, 'Secret of Evermore', 'SNES/Super Famicom', 3, 3976, 3976, 3976, 41, 0, 'Action RPG', 'Square', 'Squaresoft', '1995-10-01', 'Secret of Evermore is an action role-playing game developed and published by Squaresoft for the Super Nintendo Entertainment System. It was released in North America on October 17, 1995, in Australia in February 1996, and in Europe in March 1996. A Japanese release was planned to follow the North American release by a few months but was ultimately cancelled.', 'https://media.retroachievements.org/Images/048277.png', 'https://media.retroachievements.org/Images/043435.png', 'https://media.retroachievements.org/Images/120996.png', 'https://media.retroachievements.org/Images/120998.png', 4.3),
  (56, 1143, 'R-Type III: The Third Lightning', 'SNES/Super Famicom', 3, 3884, 3884, 3884, 31, 0, 'Shoot ''em Up', 'Irem', 'Jaleco', '1993-12-10', 'R-Type III: The Third Lightning  is a 1993 side-scrolling shooter video game developed by Tamtex and first released in Japan by Irem in 1993 for the Super Famicom and in North America and Europe in 1994 for the SNES.', 'https://media.retroachievements.org/Images/064800.png', 'https://media.retroachievements.org/Images/064805.png', 'https://media.retroachievements.org/Images/035364.png', 'https://media.retroachievements.org/Images/035365.png', 4.3),
  (57, 3594, 'Super Bomberman 3', 'SNES/Super Famicom', 3, 3813, 3813, 3813, 31, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1995-04-28', 'Super Bomberman 3 is a game released for the Super Nintendo Entertainment System in 1995. It is the third installment in the Super Bomberman series, and the third Bomberman game to be released for the system. Up to five players can play at the same time. The game was released in Japan and the PAL region, but not in North America due to the closure of Hudson Soft USA.', 'https://media.retroachievements.org/Images/043553.png', 'https://media.retroachievements.org/Images/112600.png', 'https://media.retroachievements.org/Images/006603.png', 'https://media.retroachievements.org/Images/006604.png', 4.3),
  (58, 1179, 'Spider-Man & Venom: Maximum Carnage', 'SNES/Super Famicom', 3, 3801, 3801, 3801, 39, 0, 'Beat ''em Up', 'Software Creations, Acclaim', 'Acclaim, LJN Entertainment', '1994-09-16', 'Spider-Man and Venom: Maximum Carnage is a 1994 beat ''em up video game developed by Software Creations and published by Acclaim Entertainment and its subsidiary LJN for the Super Nintendo Entertainment System and Sega Genesis. The game, based on the comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.', 'https://media.retroachievements.org/Images/105532.png', 'https://media.retroachievements.org/Images/039425.png', 'https://media.retroachievements.org/Images/003623.png', 'https://media.retroachievements.org/Images/003621.png', 4.3),
  (59, 1025, 'Metal Warriors', 'SNES/Super Famicom', 3, 3754, 3754, 3754, 25, 0, NULL, 'LucasArts | Lucasfilm', 'Konami', '1995-04-01', 'Metal Warriors is a side-scrolling action-platform run and gun video game developed by LucasArts and published by Konami exclusively for the Super Nintendo Entertainment System in North America in April 1995. It is often confused by many to be a direct sequel to Cybernator, which was created by NCS Corporation and released earlier in 1992 on the console. Set in the year 2102 where dictator Venkar Amon has waged a war against the United Earth Government for three years, players assume the role of lieutenant Stone from the titular freedom-fighting group taking control of several mecha suits in a last-ditch effort to overthrow the Dark Axis military force on Earth. Its gameplay mainly consists of action and shooting mixed with mission-based exploration using a main seven-button configuration.', 'https://media.retroachievements.org/Images/050328.png', 'https://media.retroachievements.org/Images/007437.png', 'https://media.retroachievements.org/Images/008308.png', 'https://media.retroachievements.org/Images/008309.png', 4.3),
  (60, 309, 'Super Street Fighter II: The New Challengers', 'SNES/Super Famicom', 3, 3717, 3717, 3717, 36, 0, '2D Fighting', 'Capcom', 'Capcom', '1994-06-01', 'Super Street Fighter II: The New Challengers is a 1993 fighting game developed and published by Capcom for arcades. It is the fourth game in the Street Fighter II sub-series of Street Fighter games, following Street Fighter II Turbo (1992). It refines and balances the existing character roster from the previous versions, and introduces four new characters, including Fei Long, Cammy, T. Hawk, and Dee Jay. It is the first game on Capcom''s CP System II hardware, with more sophisticated graphics and audio over the original CP System hardware used in previous versions of Street Fighter II.', 'https://media.retroachievements.org/Images/119921.png', 'https://media.retroachievements.org/Images/004903.png', 'https://media.retroachievements.org/Images/004900.png', 'https://media.retroachievements.org/Images/004901.png', 4.3),
  (61, 279, 'Killer Instinct', 'SNES/Super Famicom', 3, 3685, 3685, 3685, 53, 0, '2D Fighting', 'Rare', 'Nintendo', '1995-08-30', 'Killer Instinct is a series of fighting video games originally created by Rare and published by Midway, Nintendo, and later Xbox Game Studios since the remake. The original Killer Instinct was released for arcades in 1994; the game was then released for the Super NES and Game Boy in 1995. Its sequel, Killer Instinct 2, was released for arcades in 1996; the game was then released as Killer Instinct Gold for the Nintendo 64.', 'https://media.retroachievements.org/Images/045854.png', 'https://media.retroachievements.org/Images/000169.png', 'https://media.retroachievements.org/Images/000167.png', 'https://media.retroachievements.org/Images/000040.png', 4.3),
  (62, 1198, 'Super Adventure Island', 'SNES/Super Famicom', 3, 3648, 3648, 3648, 20, 0, '2D Platforming', 'Produce!', 'Hudson Soft', '1992-01-11', 'Super Adventure Island  is a 1992 platform game developed by Produce! and published by Hudson Soft for the Super Nintendo Entertainment System. It was the first Adventure Island game released for the SNES and came out between the releases of the NES games Adventure Island II and Adventure Island 3. It was later followed by Super Adventure Island II. The game''s soundtrack was composed by Yuzo Koshiro.', 'https://media.retroachievements.org/Images/106432.png', 'https://media.retroachievements.org/Images/006291.png', 'https://media.retroachievements.org/Images/104839.png', 'https://media.retroachievements.org/Images/006293.png', 4.3),
  (63, 985, 'Kirby''s Avalanche', 'SNES/Super Famicom', 3, 3625, 3625, 3625, 46, 0, NULL, 'HAL Laboratory', 'Nintendo', '1995-02-01', 'Kirby''s Avalanche, known in Europe as Kirby''s Ghost Trap, is a puzzle video game developed by Compile and HAL Laboratory and published by Nintendo for the Super Nintendo Entertainment System. It was released in North America and Europe in February 1995. It is a Western release of the Japanese Super Puyo Puyo featuring characters from the Kirby series. There was not a Japanese release, and the game remains the only Kirby title not released there. In Europe and Australia, the game was re-released on the Wii''s Virtual Console service on July 27, 2007, and in North America on September 24, 2007. The game was re-released for the Nintendo Classics service on July 21, 2022.', 'https://media.retroachievements.org/Images/124147.png', 'https://media.retroachievements.org/Images/026559.png', 'https://media.retroachievements.org/Images/005964.png', 'https://media.retroachievements.org/Images/005965.png', 4.3),
  (64, 645, 'Captain Commando', 'SNES/Super Famicom', 3, 3546, 3546, 3546, 20, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1995-03-17', 'Captain Commando is a 1991 beat ''em up game developed and published by Capcom for arcades. It was the seventeenth game produced for the company''s CP System hardware. The game stars the titular superhero, who was originally conceived as a fictional spokesman used by Capcom USA in the company''s console games during the late 1980s. The game was included in Capcom Beat ''Em Up Bundle compilation title, which was released digitally for Nintendo Switch, PlayStation 4, Xbox One, and Windows in September 2018.', 'https://media.retroachievements.org/Images/051801.png', 'https://media.retroachievements.org/Images/002427.png', 'https://media.retroachievements.org/Images/035370.png', 'https://media.retroachievements.org/Images/039565.png', 4.3),
  (65, 593, 'NBA Jam', 'SNES/Super Famicom', 3, 3540, 3540, 3540, 28, 0, 'Sports - Basketball', 'Iguana Entertainment', 'Acclaim', '1994-03-04', 'NBA Jam is a basketball video game series based on the National Basketball Association (NBA). Initially developed as arcade games by Midway, the game found popularity with its photorealistic digitized graphics, over-the-top presentation and exaggerated style of two-on-two basketball play. The successor to Midway''s Arch Rivals, the original 1993 NBA Jam allows players to jump many times above their own height, make slam dunks that defy human capabilities, and freely shove or elbow opponents out of the way without consequences. It also featured a variety of secret characters, as well as the ability to track player records and statistics between play sessions.', 'https://media.retroachievements.org/Images/065579.png', 'https://media.retroachievements.org/Images/004697.png', 'https://media.retroachievements.org/Images/004699.png', 'https://media.retroachievements.org/Images/004698.png', 4.3),
  (66, 1156, 'SimCity', 'SNES/Super Famicom', 3, 3497, 3497, 3497, 33, 0, 'Management Simulation', 'Intelligent Systems', 'Nintendo', '1991-08-13', 'SimCity is an open-ended city-building video game franchise originally designed by Will Wright. The first game in the series, SimCity, was published by Maxis in 1989 and was followed by several sequels and many other spin-off Sim titles, including 2000''s The Sims, which itself became a best-selling computer game and franchise. Maxis developed the series independently until 1997, and continued under the ownership of Electronic Arts (EA) until 2003. EA commissioned various spinoffs from other companies during the 2000s, focusing on console and mobile releases. A 2013 EA-Maxis reboot was subject to what has been described as one of the most disastrous launches in history, which may have triggered the 2015 shutdown of Maxis Emeryville and the end of the franchise.', 'https://media.retroachievements.org/Images/050147.png', 'https://media.retroachievements.org/Images/004574.png', 'https://media.retroachievements.org/Images/004575.png', 'https://media.retroachievements.org/Images/004576.png', 4.3),
  (67, 498, 'Ninja Gaiden Trilogy', 'SNES/Super Famicom', 3, 3493, 3493, 3493, 75, 0, 'Action Platforming', 'Team Ninja', 'Koei | Tecmo', '1995-01-01', 'Ninja Gaiden  is an action game franchise created by Tecmo and featuring the ninja Ryu Hayabusa as its protagonist. The series was originally known as Ninja Ryukenden  in Japan. The word gaiden in the North American Ninja Gaiden title means side story in Japanese. The original arcade version, first two Nintendo Entertainment System games and Game Boy game were released as Shadow Warriors in PAL regions. As of 2008, the series had shipped over 7.7 million units worldwide.', 'https://media.retroachievements.org/Images/085543.png', 'https://media.retroachievements.org/Images/050034.png', 'https://media.retroachievements.org/Images/001308.png', 'https://media.retroachievements.org/Images/001309.png', 4.3),
  (68, 982, 'The King of Dragons', 'SNES/Super Famicom', 3, 3473, 3473, 3473, 62, 0, 'Beat ''em Up', 'Prism Kikaku', 'Capcom', '1994-01-01', 'The King of Dragons is a 1991 beat ''em up game developed and published by Capcom for arcades. It follows players as they control characters through the kingdom of Malus to defeat monsters led by the dragon Gildiss. It features a level advancement system, allowing character attributes to be upgraded as players progress through the game. The game''s music was composed by Yoko Shimomura.', 'https://media.retroachievements.org/Images/101561.png', 'https://media.retroachievements.org/Images/035376.png', 'https://media.retroachievements.org/Images/081295.png', 'https://media.retroachievements.org/Images/081294.png', 4.3),
  (69, 385, 'Animaniacs', 'SNES/Super Famicom', 3, 3447, 3447, 3447, 98, 0, '2D Platforming', 'Konami', 'Konami', '1994-11-01', 'Animaniacs is an American animated comedy television series created by animator Tom Ruegger and produced by Amblin Entertainment and Warner Bros. Television Animation. It originally aired on Fox''s Fox Kids block in 1993 before moving to The WB in 1995 as part of its Kids'' WB afternoon programming block until the series ended on November 14, 1998. It initially ran a total of 99 episodes, along with a direct-to-video film, Wakko''s Wish.', 'https://media.retroachievements.org/Images/046586.png', 'https://media.retroachievements.org/Images/007078.png', 'https://media.retroachievements.org/Images/007079.png', 'https://media.retroachievements.org/Images/007080.png', 4.3),
  (70, 963, 'Joe & Mac: Caveman Ninja', 'SNES/Super Famicom', 3, 3364, 3364, 3364, 37, 0, '2D Platforming', 'Data East', 'Data East', '1992-01-01', 'Joe & Mac, also known as Caveman Ninja or Caveman Ninja: Joe & Mac, is a 1991 run and gun platform game developed and published by Data East for arcades. It was later ported to the Super Nintendo Entertainment System, MS-DOS, Amiga, Nintendo Entertainment System, Game Boy, Sega Genesis and Zeebo.', 'https://media.retroachievements.org/Images/114169.png', 'https://media.retroachievements.org/Images/055373.png', 'https://media.retroachievements.org/Images/002298.png', 'https://media.retroachievements.org/Images/002300.png', 4.3),
  (71, 3227, 'Mario no Super Picross', 'SNES/Super Famicom', 3, 3345, 3345, 3345, 77, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1995-09-14', 'Mario''s Super Picross is a Super Famicom sequel to Mario''s Picross, and a part of Nintendo''s Picross video game franchise. The game is compatible with the Super Famicom Mouse. It is developed by Jupiter and Ape and published by Nintendo.', 'https://media.retroachievements.org/Images/003359.png', 'https://media.retroachievements.org/Images/003365.png', 'https://media.retroachievements.org/Images/003364.png', 'https://media.retroachievements.org/Images/003366.png', 4.3),
  (72, 1444, 'Super Bomberman 5: Gold Cartridge', 'SNES/Super Famicom', 3, 3341, 3341, 3341, 46, 0, 'Action', 'Hudson Soft', 'Hudson Soft', '1997-02-28', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/043555.png', 'https://media.retroachievements.org/Images/124841.png', 'https://media.retroachievements.org/Images/124882.png', 'https://media.retroachievements.org/Images/008472.png', 4.3),
  (73, 934, 'Harvest Moon', 'SNES/Super Famicom', 3, 3282, 3282, 3282, 83, 0, 'Life Simulation', 'Pack-In-Video', 'Natsume', '1996-08-09', 'Harvest Moon, known in Japan as Bokujō Monogatari , is a farm simulation role-playing video game developed by Amccus for the Super Nintendo Entertainment System. The game was first released in Japan by Pack-In-Video in 1996, in North America by Natsume Inc. in 1997, and in Europe by Nintendo in 1998. It is the first game in the long-running Story of Seasons series.', 'https://media.retroachievements.org/Images/106361.png', 'https://media.retroachievements.org/Images/002106.png', 'https://media.retroachievements.org/Images/002108.png', 'https://media.retroachievements.org/Images/002107.png', 4.2),
  (74, 286, 'International Superstar Soccer Deluxe', 'SNES/Super Famicom', 3, 3255, 3255, 3255, 80, 0, 'Sports - Football | Soccer', 'Konami', 'Konami', '1995-01-01', 'International Superstar Soccer Deluxe, known as Jikkyou World Soccer 2: Fighting Eleven in Japan and also known as ISS Deluxe, is a football video game and the sequel to International Superstar Soccer developed and published by Konami. The Deluxe version was published first to the SNES in 1995, then the Mega Drive in 1996 and finally the PlayStation in 1997.', 'https://media.retroachievements.org/Images/064259.png', 'https://media.retroachievements.org/Images/001289.png', 'https://media.retroachievements.org/Images/001286.png', 'https://media.retroachievements.org/Images/001287.png', 4.2),
  (75, 292, 'Knights of the Round', 'SNES/Super Famicom', 3, 3193, 3193, 3193, 25, 0, 'Beat ''em Up', 'Capcom', 'Capcom', '1991-01-01', 'Knights of the Round is a 1991 beat ''em up game developed and published by Capcom for arcades. Based loosely on the legend of King Arthur and the Knights of the Round Table, the game features an action role-playing-like level advancement system, with fighters automatically being upgraded to new weapons and armor as they advance through the game. The arcade version of the game was included in the compilations Capcom Beat ''Em Up Bundle (2018) and Capcom Arcade 2nd Stadium (2022).', 'https://media.retroachievements.org/Images/101833.png', 'https://media.retroachievements.org/Images/001293.png', 'https://media.retroachievements.org/Images/001290.png', 'https://media.retroachievements.org/Images/001291.png', 4.2),
  (76, 867, 'Cybernator', 'SNES/Super Famicom', 3, 3192, 3192, 3192, 28, 0, NULL, 'NCS', 'Konami', '1992-12-18', 'Assault Suits Valken, also known as Cybernator, is a 2D mecha action game developed by Masaya and released in 1992 for the Super Nintendo Entertainment System. The second entry in the Assault Suit series, it is a prequel to the first game, Target Earth. The game was localized and published overseas by Konami. The story follows Jake Brain who pilots a giant mecha and fights in a war engulfing the entire world.', 'https://media.retroachievements.org/Images/113702.png', 'https://media.retroachievements.org/Images/008505.png', 'https://media.retroachievements.org/Images/008506.png', 'https://media.retroachievements.org/Images/008507.png', 4.2),
  (77, 342, 'Gradius III', 'SNES/Super Famicom', 3, 3174, 3174, 3174, 56, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1990-12-21', 'Gradius III is a 1989 scrolling shooter video game developed and published by Konami for. arcades It was originally released only in Japan on December 11, 1989. It is the third game in the Gradius series. The game was ported to the Super Nintendo Entertainment System in Japan in 1990 and North America in 1991, and served as a launch title for the system in North America. The arcade version would never see the light of day in the West until it was included alongside Gradius IV in a two-in-one compilation for the PlayStation 2 and in the Gradius Collection for the PlayStation Portable.', 'https://media.retroachievements.org/Images/038427.png', 'https://media.retroachievements.org/Images/000574.png', 'https://media.retroachievements.org/Images/000571.png', 'https://media.retroachievements.org/Images/000572.png', 4.2),
  (78, 1032, 'Mighty Morphin Power Rangers: The Fighting Edition', 'SNES/Super Famicom', 3, 3083, 3083, 3083, 68, 0, '2D Fighting', 'Natsume', 'Bandai', '1995-09-01', 'Mighty Morphin Power Rangers: The Fighting Edition is a 2D competitive fighting video game based on the Mighty Morphin Power Rangers television series that was released exclusively for the Super Nintendo Entertainment System developed by Natsume Co., Ltd. and published by Bandai in 1995. Unlike previous Power Rangers video games, which had the player controlling the titular heroes, the player controls their giant robots in this title. A bootleg Genesis port is known to exist, though who actually made it is currently unknown.', 'https://media.retroachievements.org/Images/052154.png', 'https://media.retroachievements.org/Images/054265.png', 'https://media.retroachievements.org/Images/035622.png', 'https://media.retroachievements.org/Images/035623.png', 4.2),
  (79, 409, 'Hagane: The Final Conflict', 'SNES/Super Famicom', 3, 3069, 3069, 3069, 36, 0, '2D Platforming', NULL, 'Hudson Soft', '1995-06-01', 'Hagane: The Final Conflict is a 1994 action-platform video game developed by CAProduction and Red Entertainment and published by Hudson Soft for the Super Nintendo Entertainment System. The player takes on the role of a ninja cyborg named Hagane on his path to take revenge on an opposing ninja faction. The game combines traditional Japanese ninja and samurai aesthetics with a futuristic setting. The player has a wide variety of weapons, moves, and attacks at their disposal to defeat enemies and progress through the game. Hagane released to positive reception, and was compared favorably to classic side-scrolling action games. Reviewers praised the controls, art design, and challenge but criticized the quality of the graphics and sound.', 'https://media.retroachievements.org/Images/016965.png', 'https://media.retroachievements.org/Images/009302.png', 'https://media.retroachievements.org/Images/016921.png', 'https://media.retroachievements.org/Images/016923.png', 4.2),
  (80, 868, 'Darius Twin', 'SNES/Super Famicom', 3, 3049, 3049, 3049, 56, 0, 'Shoot ''em Up', 'Taito', 'Taito', '1991-11-01', 'Darius Twin is a 1991 horizontally scrolling shooter video game developed and published by Taito for the Super Nintendo Entertainment System. It is part of the Darius series. It was re-released for the Wii Virtual Console in Japan on April 13, 2010 and in North America on December 13, 2010.', 'https://media.retroachievements.org/Images/077806.png', 'https://media.retroachievements.org/Images/005312.png', 'https://media.retroachievements.org/Images/005310.png', 'https://media.retroachievements.org/Images/005311.png', 4.2),
  (81, 647, 'Mortal Kombat II', 'SNES/Super Famicom', 3, 2958, 2958, 2958, 42, 0, '2D Fighting', 'Midway', 'Acclaim', '1994-09-01', 'Mortal Kombat II is a 1993 fighting game developed and published by Midway for arcades. It was later ported to multiple home systems, including MS-DOS, Amiga, Game Boy, Game Gear, Sega Genesis, 32X, Sega Saturn, Super NES, and PlayStation, by Probe Software and Sculptured Software, and published by Acclaim Entertainment.', 'https://media.retroachievements.org/Images/054557.png', 'https://media.retroachievements.org/Images/042418.png', 'https://media.retroachievements.org/Images/003158.png', 'https://media.retroachievements.org/Images/000482.png', 4.2),
  (82, 518, 'The Ninja Warriors', 'SNES/Super Famicom', 3, 2871, 2871, 2871, 35, 0, 'Beat ''em Up', 'Natsume', 'Taito', '1994-01-28', 'The Ninja Warriors is a 1987 beat ''em up video game developed and published by Taito for arcades. The original arcade game situated one display in between projected images of two other displays, creating the appearance of a triple-wide screen. Ports were released for home systems including the Amiga, Atari ST, ZX Spectrum, Commodore 64, Amstrad CPC, PC Engine, and Mega-CD.', 'https://media.retroachievements.org/Images/087832.png', 'https://media.retroachievements.org/Images/064745.png', 'https://media.retroachievements.org/Images/035406.png', 'https://media.retroachievements.org/Images/035407.png', 4.2),
  (83, 1049, 'NBA Jam: Tournament Edition', 'SNES/Super Famicom', 3, 2859, 2859, 2859, 53, 0, NULL, 'Iguana Entertainment', 'Acclaim', '1995-02-23', 'NBA Jam is a 1993 basketball video game developed and published by Midway for arcades. It is the first entry in the NBA Jam series, and the third basketball video game released by Midway, after TV Basketball (1974) and Arch Rivals (1989). The gameplay of NBA Jam is based on Arch Rivals, which was also a 2-on-2 basketball game; however, it was the release of NBA Jam that brought mainstream success to the genre.', 'https://media.retroachievements.org/Images/004752.png', 'https://media.retroachievements.org/Images/004751.png', 'https://media.retroachievements.org/Images/004753.png', 'https://media.retroachievements.org/Images/004754.png', 4.2),
  (84, 467, 'The Magical Quest Starring Mickey Mouse', 'SNES/Super Famicom', 3, 2839, 2839, 2839, 35, 0, '2D Platforming', 'Capcom', 'Capcom', '1992-11-20', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/113723.png', 'https://media.retroachievements.org/Images/000133.png', 'https://media.retroachievements.org/Images/000114.png', 'https://media.retroachievements.org/Images/000115.png', 4.2),
  (85, 1013, 'Mario Paint', 'SNES/Super Famicom', 3, 2831, 2831, 2831, 16, 0, 'Other', 'Nintendo', 'Nintendo', '1992-07-14', 'Mario Paint is a 1992 art creation video game developed by Nintendo Research & Development 1 (R&D1) and Intelligent Systems and published by Nintendo for the Super Nintendo Entertainment System. Mario Paint consists of a raster graphics editor, an animation program, a music composer, and a point and click minigame, all of which are designed to be used with the Super NES Mouse peripheral, which the game was packaged and sold with. Per its name, the game is Mario-themed, and features sprites and sound effects that are taken from or in the vein of Super Mario World.', 'https://media.retroachievements.org/Images/107044.png', 'https://media.retroachievements.org/Images/103319.png', 'https://media.retroachievements.org/Images/103317.png', 'https://media.retroachievements.org/Images/103318.png', 4.2),
  (86, 990, 'The Legend of the Mystical Ninja', 'SNES/Super Famicom', 3, 2829, 2829, 2829, 80, 0, NULL, 'Konami', 'Konami', '1991-07-19', 'The Legend of the Mystical Ninja is a 1991 action-adventure game released by Konami for the Super Nintendo Entertainment System. It was also ported to the Game Boy Advance along with Ganbare Goemon 2: Kiteretsu Shōgun McGuiness in 2005 only in Japan.', 'https://media.retroachievements.org/Images/094384.png', 'https://media.retroachievements.org/Images/067713.png', 'https://media.retroachievements.org/Images/002549.png', 'https://media.retroachievements.org/Images/006555.png', 4.2),
  (87, 1270, 'Tiny Toon Adventures: Buster Busts Loose!', 'SNES/Super Famicom', 3, 2820, 2820, 2820, 31, 0, '2D Platforming', 'Konami', 'Konami', '1992-12-18', 'Tiny Toon Adventures: Buster Busts Loose! is a video game for the Super NES console that is based on the animated TV series Tiny Toon Adventures. It was developed and published by Konami, released in 1992 in Japan and in 1993 in Europe and North America.', 'https://media.retroachievements.org/Images/084485.png', 'https://media.retroachievements.org/Images/044320.png', 'https://media.retroachievements.org/Images/000422.png', 'https://media.retroachievements.org/Images/000423.png', 4.2),
  (88, 1153, 'Side Pocket', 'SNES/Super Famicom', 3, 2815, 2815, 2815, 38, 0, 'Sports - Billiards', 'Iguana Entertainment', 'Data East', '1993-12-01', 'Side Pocket is a pocket billiards simulation released as an arcade video game by Data East in 1986. It was ported to the Nintendo Entertainment System and Game Boy, while an enhanced remake was later released on the Sega Genesis, Super Nintendo Entertainment System, and Game Gear. The game spawned two sequels, as well as arcade spin-off series titled Pocket Gal.', 'https://media.retroachievements.org/Images/075843.png', 'https://media.retroachievements.org/Images/007525.png', 'https://media.retroachievements.org/Images/007523.png', 'https://media.retroachievements.org/Images/007524.png', 4.2),
  (89, 829, 'The Addams Family', 'SNES/Super Famicom', 3, 2658, 2658, 2658, 46, 0, '2D Platforming', 'Ocean Software', 'Ocean Software', '1992-03-01', 'The Addams Family is a fictional family created by American cartoonist Charles Addams. The Addams are an eccentric old-money clan who delight in the macabre and the grotesque and are seemingly unaware or unconcerned that other people find them bizarre or frightening. The Addams'' view in seeing their family life and interests as normal was a basis for the satire and comedy. They originally appeared in a series of 150 standalone single-panel comics, about half of which were originally published in The New Yorker between 1938 and their creator''s death in 1988. They have since appeared in other media, such as television, film, video games, comic books, a musical, and merchandise.', 'https://media.retroachievements.org/Images/099516.png', 'https://media.retroachievements.org/Images/008297.png', 'https://media.retroachievements.org/Images/008295.png', 'https://media.retroachievements.org/Images/008296.png', 4.2),
  (90, 1004, 'Lufia & The Fortress of Doom', 'SNES/Super Famicom', 3, 2644, 2644, 2644, 47, 0, 'Turn-Based RPG', 'Neverland', 'Taito', '1993-12-01', 'Lufia & the Fortress of Doom, known as Estpolis Denki  in Japan, is a role-playing video game developed by Neverland and published by Taito in 1993, for the Super Nintendo Entertainment System. It is the first title in the Lufia series of video games and the only game from the series released under the Taito label in North America.', 'https://media.retroachievements.org/Images/036053.png', 'https://media.retroachievements.org/Images/051194.png', 'https://media.retroachievements.org/Images/002412.png', 'https://media.retroachievements.org/Images/002501.png', 4.2),
  (91, 274, 'U.N. Squadron', 'SNES/Super Famicom', 3, 2625, 2625, 2625, 28, 0, 'Shoot ''em Up', 'Capcom', 'Capcom', '1991-07-26', 'U.N. Squadron, released in Japan as Area 88, is a 1989 side-scrolling shooter video game developed and published by Capcom for arcades. It was based on the manga series of the same name, though the North American release omits all references to the manga. Their mission is to stop a terrorist group known as Project 4. It was ported to multiple platforms including the Super Nintendo Entertainment System and was followed by a spiritual successor, Carrier Air Wing.', 'https://media.retroachievements.org/Images/061111.png', 'https://media.retroachievements.org/Images/001354.png', 'https://media.retroachievements.org/Images/001351.png', 'https://media.retroachievements.org/Images/001352.png', 4.2),
  (92, 1405, 'Dragon Quest I & II', 'SNES/Super Famicom', 3, 2596, 2596, 2596, 68, 0, 'Compilation, Turn-Based RPG', 'Chunsoft', 'Enix', '1993-12-18', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/038721.png', 'https://media.retroachievements.org/Images/009582.png', 'https://media.retroachievements.org/Images/009581.png', 'https://media.retroachievements.org/Images/009583.png', 4.2),
  (93, 1328, 'Wolfenstein 3D', 'SNES/Super Famicom', 3, 2593, 2593, 2593, 50, 0, 'First-Person Shooter', 'id Software', 'Imagineer', '1994-01-01', 'Wolfenstein 3D is a 1992 first-person shooter game developed by id Software and published by Apogee Software and FormGen for MS-DOS. It was inspired by the 1981 Muse Software video game Castle Wolfenstein, and is the third installment in the Wolfenstein series. In Wolfenstein 3D, the player assumes the role of Allied spy William B.J. Blazkowicz during World War II as he escapes from the Nazi German prison Castle Wolfenstein and carries out a series of crucial missions against the Nazis. The player traverses each of the game''s levels to find an elevator to the next level or kill a final boss, fighting Nazi soldiers, dogs, and other enemies with a knife and a variety of guns.', 'https://media.retroachievements.org/Images/064973.png', 'https://media.retroachievements.org/Images/030871.png', 'https://media.retroachievements.org/Images/035397.png', 'https://media.retroachievements.org/Images/035398.png', 4.2),
  (94, 1005, 'Lufia II: Rise of the Sinistrals', 'SNES/Super Famicom', 3, 2581, 2581, 2581, 64, 0, 'Turn-Based RPG', 'Neverland', 'Natsume, Taito', '1996-08-31', 'Lufia II: Rise of the Sinistrals, known as Estpolis Denki II  in Japan, and as Lufia in Europe and Australia, is a role-playing video game with puzzle elements developed by Neverland and published in Japan in 1995 by Taito, and in North America and Europe in 1996 by Natsume and Nintendo respectively, for the Super Nintendo Entertainment System. It is the second game in the Lufia series.', 'https://media.retroachievements.org/Images/048270.png', 'https://media.retroachievements.org/Images/048202.png', 'https://media.retroachievements.org/Images/003422.png', 'https://media.retroachievements.org/Images/003423.png', 4.2),
  (95, 3362, 'Picross NP Vol. 1', 'SNES/Super Famicom', 3, 2555, 2555, 2555, 27, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-04-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/024811.png', 'https://media.retroachievements.org/Images/024930.png', 'https://media.retroachievements.org/Images/002810.png', 'https://media.retroachievements.org/Images/008210.png', 4.2),
  (96, 1344, 'X-Men: Mutant Apocalypse', 'SNES/Super Famicom', 3, 2544, 2544, 2544, 47, 0, 'Action, Platforming', 'Capcom', 'Capcom', '1994-11-01', 'X-Men: Mutant Apocalypse is an action game developed and published by Capcom for the Super Nintendo Entertainment System in 1994. The game is based on the X-Men comic book franchise from Marvel Comics. It was the first game Capcom released based on the franchise, released a month before the fighting game titled X-Men: Children of the Atom, also released in 1994.', 'https://media.retroachievements.org/Images/074997.png', 'https://media.retroachievements.org/Images/004292.png', 'https://media.retroachievements.org/Images/035400.png', 'https://media.retroachievements.org/Images/039566.png', 4.2),
  (97, 241, 'Biker Mice From Mars', 'SNES/Super Famicom', 3, 2472, 2472, 2472, 40, 0, 'Kart Racing', 'Konami', 'Konami', '1994-12-01', 'Biker Mice from Mars is an American animated series created by Rick Ungar. The series premiered in syndication the week of September 19, 1993. It consists of three seasons of 65 episodes, with the final episode airing in syndication the week of February 24, 1996.', 'https://media.retroachievements.org/Images/052427.png', 'https://media.retroachievements.org/Images/002818.png', 'https://media.retroachievements.org/Images/002816.png', 'https://media.retroachievements.org/Images/002817.png', 4.2),
  (98, 566, 'Shadowrun', 'SNES/Super Famicom', 3, 2458, 2458, 2458, 92, 0, 'Action RPG', 'Beam Software', 'Data East, Laser Beam Entertainment', '1993-05-01', 'Shadowrun is a science fantasy tabletop role-playing game set in an alternate future in which cybernetics, magic and fantasy creatures co-exist. It combines genres of cyberpunk, urban fantasy, and crime, with occasional elements of conspiracy, horror, and detective fiction. From its inception in 1989, it has spawned a franchise that includes a series of novels, a collectible card game, two miniature-based tabletop wargames, and multiple video games.', 'https://media.retroachievements.org/Images/120102.png', 'https://media.retroachievements.org/Images/078301.png', 'https://media.retroachievements.org/Images/000510.png', 'https://media.retroachievements.org/Images/000451.png', 4.2),
  (99, 296, 'Mickey and Donald''s Magical Adventure 3', 'SNES/Super Famicom', 3, 2407, 2407, 2407, 38, 0, '2D Platforming', 'Capcom', 'Capcom', '1995-12-08', 'The Nintendo Entertainment System has a library of 1370 officially licensed games released during their lifespans, plus 7 official multicarts and 2 championship cartridges. Of these, 672 were released exclusively in Japan, 187 were released exclusively in North America, and 19 were released exclusively in PAL countries. Worldwide, 521 games were released.', 'https://media.retroachievements.org/Images/113716.png', 'https://media.retroachievements.org/Images/000864.png', 'https://media.retroachievements.org/Images/001303.png', 'https://media.retroachievements.org/Images/001302.png', 4.2),
  (100, 3438, 'Rockman & Forte', 'SNES/Super Famicom', 3, 2397, 2397, 2397, 37, 0, '2D Platforming', 'Capcom', 'Capcom', '1998-04-24', 'Mega Man & Bass is a 1998 action game developed and published by Capcom. It is a spin-off game in the original Mega Man series, and was originally released in Japan for the Super Famicom on April 24, 1998. It was later ported to the Game Boy Advance in 2002, and released internationally the following year.', 'https://media.retroachievements.org/Images/028133.png', 'https://media.retroachievements.org/Images/002189.png', 'https://media.retroachievements.org/Images/002188.png', 'https://media.retroachievements.org/Images/002187.png', 4.2),
  (101, 1277, 'Top Gear 2', 'SNES/Super Famicom', 3, 2376, 2376, 2376, 111, 0, 'Arcade Racing', 'Gremlin Graphics', 'Kemco', '1993-08-08', 'Top Gear 2 is a racing video game developed and published by Gremlin Interactive. A direct sequel to the 1992 game Top Gear, it was first released by Kemco for the SNES in North America in September 1993, and then the Super Famicom in Japan on December 22. It was later ported to the Amiga and Amiga CD32 in September 1994 by Gremlin Interactive, and to the Sega Genesis in September by Vic Tokai. While more realistic than its predecessor, Top Gear 2 maintained the arcade-style gameplay the series is known for.', 'https://media.retroachievements.org/Images/046591.png', 'https://media.retroachievements.org/Images/007505.png', 'https://media.retroachievements.org/Images/035389.png', 'https://media.retroachievements.org/Images/035390.png', 4.2),
  (102, 259, 'Final Fantasy II', 'SNES/Super Famicom', 3, 2341, 2341, 2341, 21, 0, NULL, 'Square', 'Squaresoft', '1991-11-23', 'Final Fantasy II is a 1988 role-playing video game developed and published by Square for the Family Computer as the second installment of the Final Fantasy series. It was ported to and remade for WonderSwan Color, PlayStation, Game Boy Advance, PlayStation Portable, and mobile phones. Originally exclusive to Japan, later versions were released internationally, including the 2021 Final Fantasy Pixel Remaster version. The story follows the warrior Firion and his allies as they join a rebellion against the expanding Palamecian Empire. The gameplay is similar to the original game with an overworld and dungeon exploration, but its combat design is changed to a usage-based growth system where characters'' statistics increase according to how they are used or acquired.', 'https://media.retroachievements.org/Images/074336.png', 'https://media.retroachievements.org/Images/049539.png', 'https://media.retroachievements.org/Images/000749.png', 'https://media.retroachievements.org/Images/000750.png', 4.2),
  (103, 2374, 'Clock Tower', 'SNES/Super Famicom', 3, 2333, 2333, 2333, 38, 0, 'Point-and-Click Adventure, Survival Horror', 'Human Entertainment', 'Human Entertainment', '1995-09-14', 'Clock Tower is a point-and-click survival horror video game developed and published by Human Entertainment for the Super Famicom in 1995. It is the first installment in the Clock Tower series. The story follows orphan Jennifer Simpson soon after she is adopted by the Barrows family along with other orphaned girls. Shortly after arriving at the Barrows family manor, one of the other children is killed by a stalker called Scissorman. Jennifer must then explore the Barrows Mansion to find a way to escape while evading Scissorman, leading to one of the game''s multiple endings. Clock Tower utilizes a point-and-click interface with the player controlling a cursor to direct Jennifer''s actions.', 'https://media.retroachievements.org/Images/042130.png', 'https://media.retroachievements.org/Images/096952.png', 'https://media.retroachievements.org/Images/003031.png', 'https://media.retroachievements.org/Images/003030.png', 4.2),
  (104, 423, 'Battletoads and Double Dragon: The Ultimate Team', 'SNES/Super Famicom', 3, 2332, 2332, 2332, 21, 0, 'Beat ''em Up', 'Rare', 'Tradewest', '1993-10-01', 'Battletoads/Double Dragon is a 1993 beat ''em up developed by Rare and published by Tradewest. It was originally released for the Nintendo Entertainment System and later ported to the Mega Drive/Genesis, Super NES, and Game Boy. The SNES version was released on the Nintendo Classics service in September 2024; it was the game''s first re-release as it was not released on the Rare Replay collection.', 'https://media.retroachievements.org/Images/083729.png', 'https://media.retroachievements.org/Images/003412.png', 'https://media.retroachievements.org/Images/003410.png', 'https://media.retroachievements.org/Images/003411.png', 4.2),
  (105, 2610, 'Parodius: Non-Sense Fantasy', 'SNES/Super Famicom', 3, 2266, 2266, 2266, 88, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1992-04-07', 'Parodius! From Myth to Laughter, released in Japan as Parodius Da! Shinwa kara Owarai e and outside Japan as Parodius, is a shoot ''em up arcade video game and the second title in the Parodius series produced by Konami. The European SNES, Sega Saturn and PlayStation versions are also known as Parodius: Non-Sense Fantasy. The gameplay is stylistically very similar to the Gradius series, but the graphics and music are intentionally absurd.', 'https://media.retroachievements.org/Images/089920.png', 'https://media.retroachievements.org/Images/094940.png', 'https://media.retroachievements.org/Images/007388.png', 'https://media.retroachievements.org/Images/007389.png', 4.2),
  (106, 390, 'Ardy Lightfoot', 'SNES/Super Famicom', 3, 2247, 2247, 2247, 44, 0, '2D Platforming', 'ASCII Entertainment', 'Titus Interactive', '1993-11-26', 'Ardy Lightfoot is a 2D side-scrolling platform game released on the Super Nintendo Entertainment System in 1993 in Japan and 1994 in the west. It was developed by ASCII and published by Titus France in North America and Europe.', 'https://media.retroachievements.org/Images/111495.png', 'https://media.retroachievements.org/Images/004420.png', 'https://media.retroachievements.org/Images/004421.png', 'https://media.retroachievements.org/Images/004419.png', 4.2),
  (107, 986, 'Kirby''s Dream Course', 'SNES/Super Famicom', 3, 2232, 2232, 2232, 46, 0, 'Sports - Golf', 'HAL Laboratory', 'Nintendo', '1994-09-21', 'Kirby''s Dream Course is a 1994 miniature golf video game developed by HAL Laboratory and Nintendo EAD and published by Nintendo for the Super Nintendo Entertainment System (SNES). A spin-off of the Kirby series and the first released for the SNES, players control the pink spherical character Kirby through a series of courses by launching him towards the goal hole at the end. Kirby can hit enemies to collect power-ups that grant him unique abilities, such as those that allow him to destroy certain obstacles or fly around the level.', 'https://media.retroachievements.org/Images/105378.png', 'https://media.retroachievements.org/Images/065001.png', 'https://media.retroachievements.org/Images/002883.png', 'https://media.retroachievements.org/Images/002885.png', 4.2),
  (108, 2620, 'Skyblazer', 'SNES/Super Famicom', 3, 2222, 2222, 2222, 46, 0, '2D Platforming, Action', 'Ukiyotei', 'Sony Imagesoft', '1994-01-01', 'Skyblazer is a platform video game published by Sony Imagesoft, released in early 1994 for the Super Nintendo Entertainment System. It involves Sky, the Skyblazer hero searching for Ashura, the Lord of War, who had kidnapped the sorceress Ariana.', 'https://media.retroachievements.org/Images/124574.png', 'https://media.retroachievements.org/Images/124214.png', 'https://media.retroachievements.org/Images/035382.png', 'https://media.retroachievements.org/Images/035383.png', 4.2),
  (109, 1012, 'Magic Sword', 'SNES/Super Famicom', 3, 2194, 2194, 2194, 57, 0, 'Hack and Slash', 'Capcom', 'Capcom', '1992-05-29', 'Magic Sword: Heroic Fantasy (マジックソード) is a 1990 hack and slash video game developed and published by Capcom for arcades. The player is cast as a hero who fights through a mystical tower to save the world. The player can use a sword, axe or magic, and can also rescue and recruit potential allies of various character classes, each with special abilities.', 'https://media.retroachievements.org/Images/119073.png', 'https://media.retroachievements.org/Images/014991.png', 'https://media.retroachievements.org/Images/014988.png', 'https://media.retroachievements.org/Images/014989.png', 4.2),
  (110, 352, 'Final Fight Guy', 'SNES/Super Famicom', 3, 2181, 2181, 2181, 31, 0, NULL, 'Capcom', 'Capcom', '1992-03-20', 'Final Fight is a 1989 beat ''em up game developed and published by Capcom for arcades. It is the seventh title released for the CP System hardware. Set in the fictional Metro City, the player controls one of three street fighters: former pro wrestler and city mayor Mike Haggar, expert brawler Cody Travers, and modern-day ninja Guy. The trio set out to rescue Jessica when she is kidnapped by the Mad Gear Gang.', 'https://media.retroachievements.org/Images/014627.png', 'https://media.retroachievements.org/Images/125202.png', 'https://media.retroachievements.org/Images/001263.png', 'https://media.retroachievements.org/Images/001264.png', 4.2),
  (111, 424, 'Battletoads in Battlemaniacs', 'SNES/Super Famicom', 3, 2155, 2155, 2155, 23, 0, NULL, NULL, 'Tradewest', '1993-06-01', 'Battletoads in Battlemaniacs is a beat ''em up platform game developed by Rare for the Super Nintendo Entertainment System. Part of the Battletoads series, the game was released in North America by Tradewest in June 1993, in Europe by Nintendo in October 1993 and in Japan by Masaya on January 7, 1994. It was also ported for the Master System and released exclusively in Brazil. It was released around the same time as Battletoads/Double Dragon, another installment in the series. The game received its first official re-release on the Nintendo Classics service on February 21, 2024, as it was not included in the Rare Replay collection for the Xbox One.', 'https://media.retroachievements.org/Images/106494.png', 'https://media.retroachievements.org/Images/000647.png', 'https://media.retroachievements.org/Images/000689.png', 'https://media.retroachievements.org/Images/000690.png', 4.2),
  (112, 1134, 'RoboCop Versus The Terminator', 'SNES/Super Famicom', 3, 2072, 2072, 2072, 26, 0, 'Run & Gun', 'Interplay Entertainment', 'Virgin Interactive', '1993-01-01', 'RoboCop Versus The Terminator is a run and gun game released for the Sega Genesis, Super Nintendo Entertainment System, Master System, and Game Gear in 1993, with a port to the Game Boy in 1994. It is based on the 1992 four-issue comic book mini-series of the same name, which is a crossover between the RoboCop and Terminator franchises. Despite their likenesses being shown on packaging, the actors who portrayed the titular characters did not reprise their roles in this game.', 'https://media.retroachievements.org/Images/077330.png', 'https://media.retroachievements.org/Images/027611.png', 'https://media.retroachievements.org/Images/027608.png', 'https://media.retroachievements.org/Images/027609.png', 4.1),
  (113, 418, 'Batman Forever', 'SNES/Super Famicom', 3, 2059, 2059, 2059, 44, 0, 'Beat ''em Up', 'Probe Entertainment', 'Acclaim', '1995-08-01', 'Batman Forever is a 1995 American superhero film based on the DC Comics character Batman by Bob Kane and Bill Finger. It is the third installment of the Batman film series, acting as a standalone sequel to Batman Returns. Directed by Joel Schumacher and produced by Tim Burton and Peter MacGregor-Scott, it stars Val Kilmer as Bruce Wayne / Batman, replacing Michael Keaton, alongside Jim Carrey, Tommy Lee Jones, Nicole Kidman, and Chris O''Donnell. The film follows Batman as he attempts to prevent the Riddler (Carrey) and Two-Face (Jones) from uncovering his secret identity and extracting information from the minds of Gotham City''s residents, while at the same time navigating his feelings for psychologist Dr. Chase Meridian (Kidman) and adopting orphaned acrobat Dick Grayson (O''Donnell)—who becomes his partner and best friend, Robin.', 'https://media.retroachievements.org/Images/120214.png', 'https://media.retroachievements.org/Images/052554.png', 'https://media.retroachievements.org/Images/005801.png', 'https://media.retroachievements.org/Images/052555.png', 4.1),
  (114, 573, 'The Great Circus Mystery Starring Mickey & Minnie', 'SNES/Super Famicom', 3, 2040, 2040, 2040, 53, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-10-01', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/113713.png', 'https://media.retroachievements.org/Images/001269.png', 'https://media.retroachievements.org/Images/001266.png', 'https://media.retroachievements.org/Images/001267.png', 4.1),
  (115, 1274, 'Tom and Jerry', 'SNES/Super Famicom', 3, 2001, 2001, 2001, 33, 0, '2D Platforming', 'RSP', 'Hi-Tech Expressions', '1993-01-01', 'Tom and Jerry is an American animated media franchise and series of comedy short films created in 1940 by William Hanna and Joseph Barbera. Best known for its 161 theatrical short films produced by Metro-Goldwyn-Mayer, the series centers on the rivalry between a cat named Tom and a mouse named Jerry. Many shorts also feature several recurring characters.', 'https://media.retroachievements.org/Images/052088.png', 'https://media.retroachievements.org/Images/002603.png', 'https://media.retroachievements.org/Images/035561.png', 'https://media.retroachievements.org/Images/035562.png', 4.1),
  (116, 605, 'Street Fighter Alpha 2', 'SNES/Super Famicom', 3, 1977, 1977, 1977, 93, 0, '2D Fighting', 'Capcom', 'Capcom', '1996-11-01', 'Street Fighter Alpha 2, known as Street Fighter Zero 2 in Japan, Asia, South America, and Oceania, is a 1996 fighting game developed and published by Capcom for arcades. The game is the sequel to the previous year''s Street Fighter Alpha: Warriors'' Dreams and features a number of improvements, such as new attacks, stages, endings, and gameplay features. It was ported to the PlayStation, Sega Saturn and Super Nintendo home consoles globally in 1996, and later a Windows port. It was followed by Street Fighter Alpha 3 in 1998.', 'https://media.retroachievements.org/Images/049776.png', 'https://media.retroachievements.org/Images/006430.png', 'https://media.retroachievements.org/Images/001343.png', 'https://media.retroachievements.org/Images/001344.png', 4.1),
  (117, 1240, 'Super Tennis', 'SNES/Super Famicom', 3, 1977, 1977, 1977, 43, 0, 'Sports - Tennis', 'Tokyo Shoseki', 'Nintendo, Tonkin House', '1991-08-30', 'Super Tennis is a 1991 tennis video game developed by Tose and published by Tonkin House for the Super Nintendo Entertainment System. Nintendo localized the game and released it outside Japan. It utilizes mode 7 graphics.', 'https://media.retroachievements.org/Images/014908.png', 'https://media.retroachievements.org/Images/004701.png', 'https://media.retroachievements.org/Images/004703.png', 'https://media.retroachievements.org/Images/004702.png', 4.1),
  (118, 399, 'Super Double Dragon', 'SNES/Super Famicom', 3, 1973, 1973, 1973, 14, 0, 'Beat ''em Up', 'Technōs Japan', 'Tradewest', '1992-10-16', 'Super Double Dragon is a side-scrolling beat-''em-up video game released by Technōs Japan for the Super Nintendo Entertainment System in Japan in 1992. It was published by Tradewest in North America the same year and the PAL region in 1993. Super Double Dragon is the fourth console game in the Double Dragon series developed by Technōs Japan, following Double Dragon III: The Sacred Stones for the NES. The game did not have an arcade release and was made specifically for the home market.', 'https://media.retroachievements.org/Images/004120.png', 'https://media.retroachievements.org/Images/000590.png', 'https://media.retroachievements.org/Images/035659.png', 'https://media.retroachievements.org/Images/035660.png', 4.1),
  (119, 450, 'Breath of Fire II', 'SNES/Super Famicom', 3, 1957, 1957, 1957, 87, 0, NULL, 'Capcom', 'Capcom', '1995-01-01', 'Breath of Fire II is a role-playing video game developed and published by Capcom. First released in 1994, the game was licensed to Laguna for European release in 1996. It is the second entry in the Breath of Fire series. It was later ported to Game Boy Advance and re-released worldwide. The game was released on Wii''s Virtual Console in North America on August 27, 2007. Nintendo of Europe''s website mistakenly announced it for release on July 27, 2007, but it was in fact released two weeks later, on August 10, 2007. In 2013, it was released for the Wii U Virtual Console. In 2016, it was released for the New Nintendo 3DS Virtual Console. In 2019, it was released for the Nintendo Switch SNES games library.', 'https://media.retroachievements.org/Images/008647.png', 'https://media.retroachievements.org/Images/097753.png', 'https://media.retroachievements.org/Images/051035.png', 'https://media.retroachievements.org/Images/051034.png', 4.1),
  (120, 268, 'Toy Story', 'SNES/Super Famicom', 3, 1926, 1926, 1926, 31, 0, '2D Platforming', 'Traveller''s Tales', 'Disney Interactive Studios', '1995-12-01', 'Toy Story is a 1995 American animated adventure comedy film produced by Pixar Animation Studios for Walt Disney Pictures. The first entirely computer-animated feature film, as well as the first feature film from Pixar, it was directed by John Lasseter and written by Joss Whedon, Andrew Stanton, Joel Cohen, and Alec Sokolow. The film features the voices of Tom Hanks, Tim Allen, Annie Potts, John Ratzenberger, Don Rickles, Wallace Shawn, and Jim Varney. Taking place in a world where toys come to life when humans are not present, Toy Story follows an old-fashioned pullstring cowboy doll named Woody (Hanks), and a modern space cadet action figure, Buzz Lightyear (Allen), as Woody develops jealousy towards Buzz when he becomes their owner Andy''s favorite toy.', 'https://media.retroachievements.org/Images/065388.png', 'https://media.retroachievements.org/Images/002313.png', 'https://media.retroachievements.org/Images/002309.png', 'https://media.retroachievements.org/Images/002310.png', 4.1),
  (121, 1229, 'Super R-Type', 'SNES/Super Famicom', 3, 1923, 1923, 1923, 40, 0, 'Shoot ''em Up', 'Irem', 'Irem', '1991-09-01', 'Super R-Type is a scrolling shooter video game developed and published by Irem for the Super Nintendo Entertainment System. It was released in Japan and North America in 1991, Europe in 1992, and Brazil in 1993 by Nintendo. It is a partial port of R-Type II, borrowing stages and enemies, but introducing several of its own. The game has been re-released on the Wii Virtual Console in 2008, and on the Nintendo Classics service in 2024.', 'https://media.retroachievements.org/Images/087968.png', 'https://media.retroachievements.org/Images/007140.png', 'https://media.retroachievements.org/Images/007141.png', 'https://media.retroachievements.org/Images/007142.png', 4.1),
  (122, 3248, 'Run Saber', 'SNES/Super Famicom', 3, 1919, 1919, 1919, 22, 0, '2D Platforming', 'Horisoft', 'Atlus', '1993-06-08', 'Run Saber is a side-scrolling action game developed by Horisoft and published by Atlus for the Super Nintendo Entertainment System. The game was released in North America on June 8, 1993, and in Europe in 1993. Run Saber features side-scrolling fighting as the two main heroes, Allen and Sheena, the Run Sabers, fight to save the planet. The gameplay is similar to Strider, Valis and some elements of Psycho Dream.', 'https://media.retroachievements.org/Images/110732.png', 'https://media.retroachievements.org/Images/003599.png', 'https://media.retroachievements.org/Images/029127.png', 'https://media.retroachievements.org/Images/003596.png', 4.1),
  (123, 989, 'Lamborghini American Challenge', 'SNES/Super Famicom', 3, 1910, 1910, 1910, 76, 0, 'Racing', 'Titus Interactive', 'Titus Interactive', '1993-01-01', 'Lamborghini American Challenge is a 1992 racing video game developed and published by Titus France for the Amiga, Amstrad CPC, Atari ST, Commodore 64, MS-DOS, Super NES, Amiga CD32, and Game Boy.', 'https://media.retroachievements.org/Images/046979.png', 'https://media.retroachievements.org/Images/006024.png', 'https://media.retroachievements.org/Images/006022.png', 'https://media.retroachievements.org/Images/006023.png', 4.1),
  (124, 380, 'Alien vs. Predator', 'SNES/Super Famicom', 3, 1898, 1898, 1898, 23, 0, NULL, 'Jorudan', 'Activision', '1993-09-01', 'Alien vs. Predator is a science fiction action horror media franchise created by comic book writers Randy Stradley and Chris Warner. The series is a crossover between, and part of, the larger Alien and Predator franchises, depicting the two species — Xenomorph (Alien) and Yautja (Predator) — as being in conflict with one another.', 'https://media.retroachievements.org/Images/119886.png', 'https://media.retroachievements.org/Images/008158.png', 'https://media.retroachievements.org/Images/018426.png', 'https://media.retroachievements.org/Images/018427.png', 4.1),
  (125, 888, 'Earthworm Jim 2', 'SNES/Super Famicom', 3, 1876, 1876, 1876, 47, 0, '2D Platforming', 'Shiny Entertainment', 'Playmates Interactive Entertainment', '1995-11-15', 'Earthworm Jim 2 is a 1995 run and gun platform game. It is the sequel to Earthworm Jim, and the second and final game in the Earthworm Jim series developed by original creators Doug TenNapel, David Perry, and Shiny Entertainment. It was released in late 1995 and early 1996 depending on the region and video game console, initially for the Sega Genesis and Super Nintendo Entertainment System, before being ported to other platforms.', 'https://media.retroachievements.org/Images/118352.png', 'https://media.retroachievements.org/Images/055372.png', 'https://media.retroachievements.org/Images/006671.png', 'https://media.retroachievements.org/Images/006696.png', 4.1),
  (126, 7886, 'Cyber Citizen Shockman Zero', 'SNES/Super Famicom', 3, 1868, 1868, 1868, 34, 0, '2D Platforming', NULL, NULL, '1997-03-20', 'Cyber Citizen Shockman Zero  is a 1997 game for the Satellaview addon for the Super Famicom. It is a side-scrolling beat-''em-up developed by Masaya and published by NCS. It is the fourth and final game in the Cyber Citizen Shockman series, and the first on the SFC. The previous entries in the series were for the PC-Engine.', 'https://media.retroachievements.org/Images/052428.png', 'https://media.retroachievements.org/Images/052553.png', 'https://media.retroachievements.org/Images/052429.png', 'https://media.retroachievements.org/Images/052430.png', 4.1),
  (127, 3409, 'Raiden Trad', 'SNES/Super Famicom', 3, 1860, 1860, 1860, 64, 0, 'Shoot ''em Up', 'Seibu Kaihatsu', 'Electro Brain', '1992-04-01', 'Raiden is a 1990 vertically scrolling shooter video game developed by Seibu Kaihatsu and published by Tecmo for arcades. The game''s story takes place in the year 2090, when an alien species known as the Crystals invaded Earth. Players assume the roles of the Vanquish Crystal Defense pilot duo, taking control of two state of the art Fighting Thunders aircraft to defeat the Crystals and save the Earth.', 'https://media.retroachievements.org/Images/019717.png', 'https://media.retroachievements.org/Images/015101.png', 'https://media.retroachievements.org/Images/016806.png', 'https://media.retroachievements.org/Images/016807.png', 4.1),
  (128, 306, 'Mickey Mania: The Timeless Adventures of Mickey Mouse', 'SNES/Super Famicom', 3, 1820, 1820, 1820, 20, 0, '2D Platforming', 'Traveller''s Tales', 'Sony Imagesoft', '1994-01-01', 'Mickey Mania: The Timeless Adventures of Mickey Mouse is a 1994 platform video game developed by Traveller''s Tales and published by Sony Imagesoft for the Super NES, Sega Genesis, and Sega CD. In the game, the player controls Mickey Mouse, who must navigate through various side-scrolling levels, each designed and based on classic Mickey Mouse cartoons.', 'https://media.retroachievements.org/Images/059996.png', 'https://media.retroachievements.org/Images/026300.png', 'https://media.retroachievements.org/Images/001298.png', 'https://media.retroachievements.org/Images/001299.png', 4.1),
  (129, 1113, 'Prince of Persia', 'SNES/Super Famicom', 3, 1776, 1776, 1776, 40, 0, 'Cinematic Platforming', 'Arsys Software', 'Konami', '1992-01-11', 'Prince of Persia is a video game franchise created by Jordan Mechner. It is centered around a series of action-adventure games focused on various incarnations of the eponymous Prince, set in ancient and medieval Persia.', 'https://media.retroachievements.org/Images/094963.png', 'https://media.retroachievements.org/Images/048229.png', 'https://media.retroachievements.org/Images/039570.png', 'https://media.retroachievements.org/Images/039569.png', 4.1),
  (130, 1146, 'Saturday Night Slam Masters', 'SNES/Super Famicom', 3, 1776, 1776, 1776, 39, 0, 'Sports - Wrestling', 'Capcom', 'Capcom', '1994-03-30', 'Saturday Night Slam Masters, known in Japan as Muscle Bomber: The Body Explosion, is a 1993 pro wrestling fighting game developed and published by Capcom for arcades. The game features character designs by manga artist Tetsuo Hara, famous for Fist of the North Star.', 'https://media.retroachievements.org/Images/072539.png', 'https://media.retroachievements.org/Images/004750.png', 'https://media.retroachievements.org/Images/004742.png', 'https://media.retroachievements.org/Images/004743.png', 4.1),
  (131, 3228, 'Mario''s Early Years: Fun With Letters', 'SNES/Super Famicom', 3, 1775, 1775, 1775, 17, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-10-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120937.png', 'https://media.retroachievements.org/Images/017202.png', 'https://media.retroachievements.org/Images/017203.png', 'https://media.retroachievements.org/Images/017204.png', 4.1),
  (132, 1016, 'Marvel Super Heroes: War of the Gems', 'SNES/Super Famicom', 3, 1773, 1773, 1773, 84, 0, '2D Platforming', 'Capcom', 'Capcom', '1996-11-01', 'Marvel Super Heroes in War of the Gems  is a 1996 beat-''em-up platform game developed by Capcom for the Super Nintendo Entertainment System, based on the events of Marvel Comics'' series The Infinity Gauntlet and The Infinity War. In the game''s plot, Adam Warlock calls upon Earth''s greatest superheroes to seek out the Infinity Gems before they fall into the wrong hands.', 'https://media.retroachievements.org/Images/075412.png', 'https://media.retroachievements.org/Images/006890.png', 'https://media.retroachievements.org/Images/035377.png', 'https://media.retroachievements.org/Images/035378.png', 4.1),
  (133, 3351, 'Panel de Pon', 'SNES/Super Famicom', 3, 1763, 1763, 1763, 51, 0, NULL, 'Intelligent Systems', 'Nintendo', '1995-10-27', 'Puzzle League, known as Panel de Pon in Japan, is a series of video games published by Nintendo for its various video game consoles. The series began with Panel de Pon in Japan, named Tetris Attack in North America, and has since been adapted to many other consoles. The core gameplay of each version is the same in each game, but branding, presentation details and console-specific features have varied.', 'https://media.retroachievements.org/Images/112289.png', 'https://media.retroachievements.org/Images/064929.png', 'https://media.retroachievements.org/Images/015296.png', 'https://media.retroachievements.org/Images/015297.png', 4.1),
  (134, 1278, 'Top Gear 3000', 'SNES/Super Famicom', 3, 1757, 1757, 1757, 40, 0, 'Racing', 'Gremlin Graphics', 'Kemco', '1995-02-01', 'Top Gear 3000, later released in Japan as The Planet''s Champ: TG3000 , is a racing video game developed by Gremlin Interactive and published by Kemco for the Super Nintendo Entertainment System. It is the third game in the original Top Gear trilogy, and the last in the series to be developed by Gremlin. 3000 heavily resembles the previous Top Gear 2, but is set in the distant future.', 'https://media.retroachievements.org/Images/052104.png', 'https://media.retroachievements.org/Images/000241.png', 'https://media.retroachievements.org/Images/035391.png', 'https://media.retroachievements.org/Images/035392.png', 4.1),
  (135, 12736, '~Hack~ Super Mario World: Learn 2 Kaizo', 'SNES/Super Famicom', 3, 1748, 1748, 1748, 76, 0, '2D Platforming, Educational', 'NeXuS15', 'Hack - Super Mario World', '2017-09-20', 'Kaizo Mario World, also known as Asshole Mario, is a series of three ROM hacks of the Super Nintendo Entertainment System video game Super Mario World, created by T. Takemoto. The term Kaizo Mario World is a shortened form of the title Jisaku no Kaizō Mario o Yūjin ni Play Saseru. The series was created by Takemoto for his friend R. Kiba.', 'https://media.retroachievements.org/Images/026449.png', 'https://media.retroachievements.org/Images/026469.png', 'https://media.retroachievements.org/Images/026447.png', 'https://media.retroachievements.org/Images/026448.png', 4.1),
  (136, 395, 'Axelay', 'SNES/Super Famicom', 3, 1662, 1662, 1662, 46, 0, 'Shoot ''em Up', 'Konami', 'Konami', '1992-09-11', 'Axelay is a 1992 scrolling shooter developed and published by Konami for the Super Nintendo Entertainment System. Set in the fictional solar system Illis where an alien empire known as Armada of Annihilation invades its planets including the Earth-like Corliss (Mother), players take control of the titular D117B space fighter craft as a last resort to stop the alien invasion by recovering its lost weaponry. The gameplay mainly consist of both vertical-scrolling and horizontal-scrolling stages in the same vein as Konami''s own Life Force, with players choosing three different weapon-types that increase in number as they progress through the game.', 'https://media.retroachievements.org/Images/050441.png', 'https://media.retroachievements.org/Images/006893.png', 'https://media.retroachievements.org/Images/035362.png', 'https://media.retroachievements.org/Images/035363.png', 4.1),
  (137, 440, 'Bonkers', 'SNES/Super Famicom', 3, 1651, 1651, 1651, 21, 0, '2D Platforming', 'Capcom', 'Capcom', '1994-12-15', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/034929.png', 'https://media.retroachievements.org/Images/004423.png', 'https://media.retroachievements.org/Images/004422.png', 'https://media.retroachievements.org/Images/004424.png', 4.1),
  (138, 3229, 'Mario''s Early Years: Fun With Numbers', 'SNES/Super Famicom', 3, 1649, 1649, 1649, 12, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-09-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120938.png', 'https://media.retroachievements.org/Images/070019.png', 'https://media.retroachievements.org/Images/017839.png', 'https://media.retroachievements.org/Images/017840.png', 4.1),
  (139, 393, 'Astérix & Obélix', 'SNES/Super Famicom', 3, 1641, 1641, 1641, 86, 0, '2D Platforming', 'Bit Managers', 'Infogrames', '1995-09-28', 'Asterix is a French comic album series about a Gaulish village which, thanks to a magic potion that enhances strength, resists the forces of Julius Caesar''s Roman Republic Army in the time after the Gallic Wars. Many adventures take the titular hero Asterix and his friend Obelix to Rome and beyond.', 'https://media.retroachievements.org/Images/120413.png', 'https://media.retroachievements.org/Images/119216.png', 'https://media.retroachievements.org/Images/017115.png', 'https://media.retroachievements.org/Images/017116.png', 4.1),
  (140, 929, 'The Great Waldo Search', 'SNES/Super Famicom', 3, 1617, 1617, 1617, 15, 0, 'Hidden Object', 'Radiance Software', 'THQ', '1992-01-01', 'Where''s Wally? The Fantastic Journey is the third Where''s Wally? book, first released in 1989. In the book Wally travels to fantasy lands in search of Wizard Whitebeard''s magical scrolls. The book introduces the second recurring Where''s Wally character, Wizard Whitebeard. Readers are also asked for the first time to find the Wizard''s scrolls.', 'https://media.retroachievements.org/Images/113709.png', 'https://media.retroachievements.org/Images/056179.png', 'https://media.retroachievements.org/Images/056182.png', 'https://media.retroachievements.org/Images/056183.png', 4.1),
  (141, 1386, 'Final Fantasy V', 'SNES/Super Famicom', 3, 1597, 1597, 1597, 116, 0, NULL, 'Square', 'Squaresoft', '1992-12-06', 'Final Fantasy V is a 1992 role-playing video game developed and published by Square for the Super Famicom. It is the fifth main installment of the Final Fantasy series. The game begins as a wanderer named Bartz investigates a fallen meteor. There, he encounters several characters, one of whom reveals the danger facing the four Crystals that control the world''s elements. These Crystals act as a seal on Exdeath, an evil sorcerer. Bartz and his party must keep the Crystals from being exploited by Exdeath''s influence and prevent his resurgence.', 'https://media.retroachievements.org/Images/070795.png', 'https://media.retroachievements.org/Images/003373.png', 'https://media.retroachievements.org/Images/003374.png', 'https://media.retroachievements.org/Images/003375.png', 4.1),
  (142, 1361, 'Ghost Sweeper Mikami: Joreishi wa Nice Body', 'SNES/Super Famicom', 3, 1596, 1596, 1596, 18, 0, '2D Platforming', 'Banirex', 'Natsume', '1993-09-23', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/049699.png', 'https://media.retroachievements.org/Images/003349.png', 'https://media.retroachievements.org/Images/003346.png', 'https://media.retroachievements.org/Images/003347.png', 4.1),
  (143, 1174, 'Sparkster', 'SNES/Super Famicom', 3, 1571, 1571, 1571, 73, 0, NULL, 'Konami', 'Konami', '1994-09-15', 'Sparkster  is a 1994 platform game developed and published by Konami for the Super Nintendo Entertainment System. It is the only game in the Rocket Knight series to be released on a Nintendo console, and was directed by Hideo Ueda. Sparkster is a sequel to the original Rocket Knight Adventures for the Sega Genesis, though it is a different game than the similarly titled Genesis sequel, Sparkster: Rocket Knight Adventures 2.', 'https://media.retroachievements.org/Images/058016.png', 'https://media.retroachievements.org/Images/113875.png', 'https://media.retroachievements.org/Images/063318.png', 'https://media.retroachievements.org/Images/063319.png', 4.1),
  (144, 9784, '~Hack~ New Super Mario World 1: The Twelve Magic Orbs', 'SNES/Super Famicom', 3, 1545, 1545, 1545, 58, 0, '2D Platforming', 'Pink Gold Peach', 'Hack - Super Mario World', '2016-08-29', 'Dragon Quest, previously published as Dragon Warrior in North America until 2005, is a series of role-playing video games created by Japanese game designer Yuji Horii, character designer Akira Toriyama, and composer Koichi Sugiyama and published by Square Enix. Since its inception, development of games in the series have been outsourced to a plethora of external companies until the tenth installment, with localized remakes and ports of later installments for the Nintendo DS, Nintendo 3DS, and Nintendo Switch being published by Nintendo outside of Japan. With its first game published in 1986, there are eleven main-series games, along with numerous spin-off games. In addition, there have been numerous manga, anime and novels published under the franchise, with nearly every game in the main series having a related adaptation.', 'https://media.retroachievements.org/Images/022110.png', 'https://media.retroachievements.org/Images/020852.png', 'https://media.retroachievements.org/Images/015506.png', 'https://media.retroachievements.org/Images/015507.png', 4.1),
  (145, 1261, 'Thomas the Tank Engine & Friends', 'SNES/Super Famicom', 3, 1521, 1521, 1521, 8, 0, 'Educational', 'Software Creations', 'THQ', '1993-09-01', 'Thomas & Friends is a British children''s television series which aired from 9 October 1984 to 20 January 2021. Based on The Railway Series books by Wilbert and Christopher Awdry, the series was developed for television by Britt Allcroft. The series centers on various anthropomorphic steam locomotives as well as other vehicles living on the fictional Island of Sodor. The show was initially filmed in live action on model sets, whereas the latter half of its run was produced using CGI. Over 500 episodes were produced over the course of 24 series.', 'https://media.retroachievements.org/Images/089849.png', 'https://media.retroachievements.org/Images/034661.png', 'https://media.retroachievements.org/Images/006993.png', 'https://media.retroachievements.org/Images/006994.png', 4.1),
  (146, 4737, 'The Firemen', 'SNES/Super Famicom', 3, 1520, 1520, 1520, 16, 0, 'Action-Adventure', 'Human Entertainment', 'Human Entertainment', '1995-03-01', 'The Firemen is an action video game developed and published by Human Entertainment for the Super Nintendo Entertainment System. It was first released in Japan in 1994, and then in Europe and Australia in 1995. In The Firemen, the player controls firemen who fight fires and save civilians. A sequel was released for the PlayStation in 1995 titled The Firemen 2: Pete & Danny.', 'https://media.retroachievements.org/Images/087674.png', 'https://media.retroachievements.org/Images/007355.png', 'https://media.retroachievements.org/Images/002397.png', 'https://media.retroachievements.org/Images/002398.png', 4.1),
  (147, 1295, 'Uniracers', 'SNES/Super Famicom', 3, 1520, 1520, 1520, 24, 0, 'Racing', 'Rockstar North', 'Nintendo', '1994-06-01', 'Uniracers is a racing game developed by DMA Design and published by Nintendo for the Super Nintendo Entertainment System in North America in December 1994 and in the PAL territories on 27 April 1995.', 'https://media.retroachievements.org/Images/059040.png', 'https://media.retroachievements.org/Images/000814.png', 'https://media.retroachievements.org/Images/000815.png', 'https://media.retroachievements.org/Images/000813.png', 4.1),
  (148, 366, 'Addams Family Values', 'SNES/Super Famicom', 3, 1509, 1509, 1509, 57, 0, NULL, 'Ocean Software', 'Ocean Software', '1995-02-01', 'Addams Family Values is a 1993 American black comedy film, based on the comic strip characters created by Charles Addams. It is the sequel to The Addams Family (1991). Directed by Barry Sonnenfeld and written by Paul Rudnick, the film features most of the cast members from the original film, including Anjelica Huston, Raul Julia, Christopher Lloyd and Christina Ricci, with Joan Cusack and Carol Kane joining the cast.', 'https://media.retroachievements.org/Images/049184.png', 'https://media.retroachievements.org/Images/003730.png', 'https://media.retroachievements.org/Images/006358.png', 'https://media.retroachievements.org/Images/006359.png', 4.1),
  (149, 926, 'Gods', 'SNES/Super Famicom', 3, 1488, 1488, 1488, 32, 0, '2D Platforming', 'The Bitmap Brothers', 'Mindscape', '1992-12-01', 'A deity or god is a supernatural being considered to be sacred and worthy of worship due to having authority over some aspect of the universe and/or life. The Oxford Dictionary of English defines deity as a god or goddess, or anything revered as divine. C. Scott Littleton defines a deity as a being with powers greater than those of ordinary humans, but who interacts with humans, positively or negatively, in ways that carry humans to new levels of consciousness, beyond the grounded preoccupations of ordinary life.', 'https://media.retroachievements.org/Images/096087.png', 'https://media.retroachievements.org/Images/095890.png', 'https://media.retroachievements.org/Images/095888.png', 'https://media.retroachievements.org/Images/095889.png', 4.1),
  (150, 2905, 'Cannon Fodder', 'SNES/Super Famicom', 3, 1474, 1474, 1474, 52, 0, 'Action, Strategy', 'Sensible Software', 'Virgin Interactive', '1994-01-01', 'Cannon Fodder is a series of war themed action games developed by Sensible Software, initially released as Cannon Fodder for the Amiga. Only two games in the series were created by Sensible, but were converted to most active systems at the time of release. A sequel, Cannon Fodder 2, was released in 1994 for Amiga and MS-DOS. A third game, Cannon Fodder 3, was made by a Russian developer and released in English in 2012.', 'https://media.retroachievements.org/Images/089451.png', 'https://media.retroachievements.org/Images/009283.png', 'https://media.retroachievements.org/Images/035368.png', 'https://media.retroachievements.org/Images/035369.png', 4.1),
  (151, 2602, 'Majuuou', 'SNES/Super Famicom', 3, 1467, 1467, 1467, 46, 0, NULL, 'Nippon Ichi Software', 'KSS', '1995-08-25', NULL, 'https://media.retroachievements.org/Images/035557.png', 'https://media.retroachievements.org/Images/124235.png', 'https://media.retroachievements.org/Images/020873.png', 'https://media.retroachievements.org/Images/007482.png', 4.1),
  (152, 555, 'Shin Kidou Senki Gundam W: Endless Duel', 'SNES/Super Famicom', 3, 1451, 1451, 1451, 25, 0, '2D Fighting', 'Natsume', 'Bandai', '1996-01-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/051792.png', 'https://media.retroachievements.org/Images/006510.png', 'https://media.retroachievements.org/Images/001304.png', 'https://media.retroachievements.org/Images/001305.png', 4.1),
  (153, 1215, 'Super E.D.F.: Earth Defense Force', 'SNES/Super Famicom', 3, 1430, 1430, 1430, 29, 0, 'Shoot ''em Up', 'Jaleco', 'Jaleco', '1991-10-25', 'E.D.F.: Earth Defense Force is a 1991 horizontally scrolling shooter video game developed and published by Jaleco for arcades. It was ported to the Super Nintendo Entertainment System as Super Earth Defense Force, dropping the two-player cooperative gaming mode while adding graphics and selectable weapons. The Super NES version was released in Japan on October 25, 1991, and in North America in January 1992. The Super NES version was eventually released on the Wii Virtual Console in Europe on October 29, 2010, and in 2011 for Japan on January 11, and North America on July 14. It was released on the Nintendo Classics service in September 2019.', 'https://media.retroachievements.org/Images/048925.png', 'https://media.retroachievements.org/Images/009242.png', 'https://media.retroachievements.org/Images/009243.png', 'https://media.retroachievements.org/Images/009244.png', 4.1),
  (154, 1244, 'Super Valis IV', 'SNES/Super Famicom', 3, 1422, 1422, 1422, 26, 0, 'Action', 'Telenet Japan', 'Razorsoft', '1992-03-27', 'Valis IV is a 1991 action-platform video game originally developed by Laser Soft and published by Telenet Japan for the PC Engine CD-ROM². A vastly different version titled Super Valis IV was published in Japan by Telenet in 1992 and in North America by Atlus Software in 1993 for the Super Nintendo Entertainment System. It is the fourth and final main entry in the eponymous series. Following on the events of Valis III, Yuko became a goddess and has watched over Vecanti since Glames'' defeat. The dark world prince Galgear, who lost self-control after acquiring a magical ring, broke from his fifteen-year imprisonment by the gods of Vecanti, kidnapping Valna and being pursued by troops led by Cham. Lena, a member of Cham''s band, is joined by her sister Amu and the prince''s father Asfal on a journey to retrieve the titular sword and defeat Galgear.', 'https://media.retroachievements.org/Images/027595.png', 'https://media.retroachievements.org/Images/001572.png', 'https://media.retroachievements.org/Images/035587.png', 'https://media.retroachievements.org/Images/035588.png', 4.1),
  (155, 3230, 'Mario''s Early Years: Preschool Fun', 'SNES/Super Famicom', 3, 1414, 1414, 1414, 15, 0, 'Educational', 'The Software Toolworks', 'Nintendo', '1994-11-01', 'The Mario''s Early Years! series is a trilogy of point-and-click educational games released on MS-DOS and Super Nintendo Entertainment System developed and published by The Software Toolworks under license from Nintendo. The three games consist of Fun with Letters, Fun with Numbers and Preschool Fun.', 'https://media.retroachievements.org/Images/120939.png', 'https://media.retroachievements.org/Images/052639.png', 'https://media.retroachievements.org/Images/019986.png', 'https://media.retroachievements.org/Images/019987.png', 4.1),
  (156, 2817, 'Super Buster Bros.', 'SNES/Super Famicom', 3, 1410, 1410, 1410, 66, 0, 'Action', 'Capcom', 'Capcom', '1992-01-01', 'Super Buster Bros., released as Super Pang outside of North America, is a cooperative two-player shooting puzzle arcade video game developed by Mitchell and released in the United States in 1990 by Capcom. It is the second game in the Pang series and was ported to the Super Nintendo Entertainment System in 1992. It is also featured in the compilations Buster Bros. Collection for the original PlayStation and Capcom Puzzle World for PlayStation Portable. It was the tenth game released for the CP System hardware.', 'https://media.retroachievements.org/Images/115462.png', 'https://media.retroachievements.org/Images/124243.png', 'https://media.retroachievements.org/Images/070948.png', 'https://media.retroachievements.org/Images/070949.png', 4.1),
  (157, 1037, 'Monopoly', 'SNES/Super Famicom', 3, 1405, 1405, 1405, 29, 0, 'Board Game', 'Sculptured Software | Iguana West', 'Parker Brothers', '1991-01-01', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/017240.png', 'https://media.retroachievements.org/Images/017238.png', 'https://media.retroachievements.org/Images/017239.png', 'https://media.retroachievements.org/Images/017365.png', 4.1),
  (158, 443, 'Brain Lord', 'SNES/Super Famicom', 3, 1404, 1404, 1404, 50, 0, 'Action RPG', 'Produce!', 'Enix', '1994-01-29', 'Brain Lord  is an action role-playing video game developed by Produce! and published by Enix for the Super NES. It was only released in Japan and North America.', 'https://media.retroachievements.org/Images/081733.png', 'https://media.retroachievements.org/Images/039064.png', 'https://media.retroachievements.org/Images/098317.png', 'https://media.retroachievements.org/Images/006261.png', 4.1),
  (159, 374, 'Aero the Acro-Bat', 'SNES/Super Famicom', 3, 1392, 1392, 1392, 126, 0, '2D Platforming', 'Iguana Entertainment', 'Sunsoft', '1993-10-01', 'Aero the Acro-Bat is a 1993 platform video game developed by Iguana Entertainment and published by Sunsoft for the Super Nintendo Entertainment System and Sega Genesis. Aero the Acro-Bat, a red anthropomorphic bat, was created by David Siller. In 2002, Metro 3D released a version of the game for the Game Boy Advance, with a battery back-up. The GBA version was titled Aero The Acro-Bat - Rascal Rival Revenge in Europe and Acrobat Kid in Japan. The Super NES version of the game was released on the Wii''s Virtual Console in the PAL region and North America in July 2010. In 2024, the Super NES version was re-released in August for Nintendo Switch, PlayStation 4, PlayStation 5, Xbox One, and Xbox Series X/S, alongside a new localization in Japanese made by Shinyuden as Aero: Acrobat Kid for the Nintendo Switch users in Japan, while the GBA version was re-released for the same platforms in November.', 'https://media.retroachievements.org/Images/075614.png', 'https://media.retroachievements.org/Images/006369.png', 'https://media.retroachievements.org/Images/006365.png', 'https://media.retroachievements.org/Images/006366.png', 4.1),
  (160, 1391, 'Trials of Mana', 'SNES/Super Famicom', 3, 1392, 1392, 1392, 100, 0, NULL, 'Square', 'Squaresoft', '1995-09-30', 'Trials of Mana, also known by its Japanese title Seiken Densetsu 3, is a 1995 action role-playing game developed and published by Square for the Super Famicom. It is the sequel to the 1993 game Secret of Mana, and is the third installment in the Mana series. Set in a high fantasy world, the game follows three heroes as they attempt to claim the legendary Mana Sword and prevent the Benevodons from being unleashed and destroying the world. It features three main plotlines and six different possible main characters, each with their own storylines, and allows two players to play simultaneously. Trials of Mana builds on the gameplay of its predecessor with multiple enhancements, including the use of a time progression system with transitions from day to night and weekday to weekday in game time, and a wide range of character classes to choose from, which provides each character with an exclusive set of skills and status progression.', 'https://media.retroachievements.org/Images/104864.png', 'https://media.retroachievements.org/Images/002847.png', 'https://media.retroachievements.org/Images/002848.png', 'https://media.retroachievements.org/Images/006100.png', 4.1),
  (161, 1150, 'Shaq-Fu', 'SNES/Super Famicom', 3, 1373, 1373, 1373, 31, 0, '2D Fighting', 'Delphine Software International', 'Electronic Arts, Playtronic', '1994-10-28', 'Shaq Fu is a 1994 fighting game developed by Delphine Software International and published by Electronic Arts for the Sega Genesis and Super Nintendo Entertainment System. Versions for the Game Gear, Game Boy, and Amiga followed in 1995. Professional basketball player Shaquille O''Neal is the player character.', 'https://media.retroachievements.org/Images/023579.png', 'https://media.retroachievements.org/Images/004850.png', 'https://media.retroachievements.org/Images/004853.png', 'https://media.retroachievements.org/Images/004852.png', 4.1),
  (162, 1099, 'Pitfall: The Mayan Adventure', 'SNES/Super Famicom', 3, 1353, 1353, 1353, 58, 0, '2D Platforming', 'Redline Games', 'Activision', '1994-11-01', 'Pitfall: The Mayan Adventure is a 1994 action-platform video game developed by Activision in conjunction with Kroyer Films. The fourth installment in the Pitfall! franchise, players assume the role of Pitfall Harry Jr. as he embarks on a journey through the Mayan jungles of Central America in an attempt to rescue Pitfall Harry, his father and the protagonist of previous entries in the series, from the evil Mayan warrior spirit Zakelua. Its gameplay mainly consists of action and platforming mixed with stage-based exploration using a main six-button configuration.', 'https://media.retroachievements.org/Images/092737.png', 'https://media.retroachievements.org/Images/096578.png', 'https://media.retroachievements.org/Images/007146.png', 'https://media.retroachievements.org/Images/007147.png', 4.1),
  (163, 1158, 'The Simpsons: Bart''s Nightmare', 'SNES/Super Famicom', 3, 1333, 1333, 1333, 25, 0, '2D Platforming', 'Sculptured Software | Iguana West', 'Acclaim', '1992-01-01', 'The Simpsons: Bart''s Nightmare is a 1992 platform video game based on the animated television series The Simpsons. Developed by Sculptured Software and published by Acclaim Entertainment, it was first released for the Super Nintendo Entertainment System in 1992, followed by the Sega Genesis in 1993. The first half of the game follows Bart Simpson as he tries to find his missing homework pages in order to escape a bizarre dream world, while the second half consists of minigames.', 'https://media.retroachievements.org/Images/109673.png', 'https://media.retroachievements.org/Images/003631.png', 'https://media.retroachievements.org/Images/003633.png', 'https://media.retroachievements.org/Images/003632.png', 4),
  (164, 9790, 'Dr. Mario', 'SNES/Super Famicom', 3, 1331, 1331, 1331, 78, 0, NULL, NULL, 'Nintendo', '1998-06-01', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/070808.png', 'https://media.retroachievements.org/Images/114804.png', 'https://media.retroachievements.org/Images/023464.png', 'https://media.retroachievements.org/Images/023465.png', 4),
  (165, 3234, 'The Mask', 'SNES/Super Famicom', 3, 1304, 1304, 1304, 26, 0, '2D Platforming', 'Black Pearl', 'Black Pearl', '1995-10-01', 'The Mask is a 1995 side-scrolling action video game developed and published by THQ subsidiary Black Pearl Software for the Super Nintendo Entertainment System which is based on the film of the same name. The film, in turn, was loosely based on the Dark Horse comic book series of the same name.', 'https://media.retroachievements.org/Images/121441.png', 'https://media.retroachievements.org/Images/007194.png', 'https://media.retroachievements.org/Images/035578.png', 'https://media.retroachievements.org/Images/035579.png', 4),
  (166, 412, 'Barbie: Super Model', 'SNES/Super Famicom', 3, 1302, 1302, 1302, 7, 0, 'Action', 'Tahoe Software Productions', 'Hi-Tech Expressions', '1993-12-01', 'Barbie: Super Model is a one or two-player educational action video game that allows the player to play as Barbie. It was released for the Genesis, Super NES, and MS-DOS in 1993.', 'https://media.retroachievements.org/Images/078520.png', 'https://media.retroachievements.org/Images/053617.png', 'https://media.retroachievements.org/Images/008710.png', 'https://media.retroachievements.org/Images/008716.png', 4),
  (167, 16121, '~Hack~ New Super Mario World 2: Around the World', 'SNES/Super Famicom', 3, 1298, 1298, 1298, 45, 0, '2D Platforming', 'Pink Gold Peach', 'Hack - Super Mario World', '2019-01-01', 'Super Mario Kart is a 1992 kart racing game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The first game in the Mario Kart series, it was released in Japan on August 27, 1992, North America on September 1, 1992, the United Kingdom in October 1992, and Europe on January 21, 1993. Selling 8.76 million copies worldwide, the game went on to become the fourth best-selling SNES game of all time. Super Mario Kart was re-released on the Wii''s Virtual Console in 2009, on the Wii U''s Virtual Console in 2013, and on the New Nintendo 3DS''s Virtual Console in 2016. Nintendo re-released Super Mario Kart in 2017 as part of the company''s Super NES Classic Edition.', 'https://media.retroachievements.org/Images/063931.png', 'https://media.retroachievements.org/Images/032596.png', 'https://media.retroachievements.org/Images/032597.png', 'https://media.retroachievements.org/Images/032598.png', 4),
  (168, 967, 'Judge Dredd', 'SNES/Super Famicom', 3, 1295, 1295, 1295, 43, 0, '2D Platforming', 'Probe Entertainment', 'Acclaim', '1995-06-16', 'Judge Joseph Dredd is a fictional character created by writer John Wagner and artist Carlos Ezquerra. He first appeared in the second issue of the British weekly anthology comic 2000 AD (1977). He is the magazine''s longest-running character, and in 1990 he got his own title, the Judge Dredd Megazine. He also appears in a number of film and video game adaptations.', 'https://media.retroachievements.org/Images/062928.png', 'https://media.retroachievements.org/Images/015324.png', 'https://media.retroachievements.org/Images/015325.png', 'https://media.retroachievements.org/Images/015326.png', 4),
  (169, 993, 'Lemmings', 'SNES/Super Famicom', 3, 1280, 1280, 1280, 123, 0, 'Puzzle', 'Sunsoft', 'Sunsoft', '1991-12-18', 'A lemming is a small rodent, usually found in or near the Arctic in tundra biomes. Lemmings form the subfamily Arvicolinae together with voles and muskrats, which form part of the superfamily Muroidea, which also includes rats, mice, hamsters and gerbils. A longstanding myth claims that they exhibit herd mentality and jump off cliffs, committing mass suicide.', 'https://media.retroachievements.org/Images/041707.png', 'https://media.retroachievements.org/Images/002222.png', 'https://media.retroachievements.org/Images/085120.png', 'https://media.retroachievements.org/Images/085121.png', 4),
  (170, 2345, '~Hack~ The Legend of Zelda: Parallel Worlds', 'SNES/Super Famicom', 3, 1277, 1277, 1277, 100, 0, 'Action-Adventure', 'Seph, Euclid, Richyawyingtmv', 'Hack - The Legend of Zelda: A Link to the Past', '2006-12-31', 'A fan game is a video game that is created by fans of a certain topic or IP. They are usually based on one, or in some cases several, video game entries or franchises. Many fan games attempt to clone or remake the original game''s design, gameplay, and characters, but it is equally common for fans to develop a unique game using another as a template. Though the quality of fan games has always varied, recent advances in computer technology and in available tools, e.g. through open source software, have made creating high-quality games easier. Fan games can be seen as user-generated content, as part of the retrogaming phenomena, and as expression of the remix culture.', 'https://media.retroachievements.org/Images/052201.png', 'https://media.retroachievements.org/Images/022021.png', 'https://media.retroachievements.org/Images/023380.png', 'https://media.retroachievements.org/Images/005044.png', 4),
  (171, 3374, 'The Pirates of Dark Water', 'SNES/Super Famicom', 3, 1255, 1255, 1255, 21, 0, 'Beat ''em Up', 'Sunsoft', 'Sunsoft', '1994-05-01', 'The Pirates of Dark Water is an American fantasy animated television series created by David Kirschner and produced by Hanna-Barbera. It premiered as a five-part miniseries on Fox Kids in early 1991 titled Dark Water. The first season, consisting of 13 episodes including the original five-part miniseries, aired on ABC from September to December 1991. A second season, consisting of eight episodes, aired in syndication in the United States from 1992 to 1993.', 'https://media.retroachievements.org/Images/065466.png', 'https://media.retroachievements.org/Images/006442.png', 'https://media.retroachievements.org/Images/006443.png', 'https://media.retroachievements.org/Images/006444.png', 4),
  (172, 1302, 'Ys III: Wanderers from Ys', 'SNES/Super Famicom', 3, 1251, 1251, 1251, 46, 0, NULL, 'Nihon Falcom', 'Sammy', '1992-01-01', 'Ys III: Wanderers from Ys is a 1989 action role-playing game developed by Nihon Falcom. It is the third game in the Ys series.', 'https://media.retroachievements.org/Images/111797.png', 'https://media.retroachievements.org/Images/002507.png', 'https://media.retroachievements.org/Images/002509.png', 'https://media.retroachievements.org/Images/002508.png', 4),
  (173, 8702, 'Strike Gunner S.T.G', 'SNES/Super Famicom', 3, 1247, 1247, 1247, 21, 0, 'Shoot ''em Up', 'Athena', 'NTV International', '1992-01-01', 'Strike Gunner S.T.G (エス・ティー・ジー) is a 1991 vertically scrolling shooter arcade game developed by Athena and published by Tecmo.', 'https://media.retroachievements.org/Images/047001.png', 'https://media.retroachievements.org/Images/014759.png', 'https://media.retroachievements.org/Images/014761.png', 'https://media.retroachievements.org/Images/014762.png', 4),
  (174, 949, 'Inspector Gadget', 'SNES/Super Famicom', 3, 1242, 1242, 1242, 7, 0, '2D Platforming', NULL, 'Hudson Soft', '1993-12-01', 'Inspector Gadget is a media franchise that began in 1983 with the DIC Entertainment animated television series Inspector Gadget. Since the original series, there have been many spin-offs based on the show, including additional animated series, video games, and films.', 'https://media.retroachievements.org/Images/118599.png', 'https://media.retroachievements.org/Images/006455.png', 'https://media.retroachievements.org/Images/006457.png', 'https://media.retroachievements.org/Images/006456.png', 4),
  (175, 940, 'Hook', 'SNES/Super Famicom', 3, 1221, 1221, 1221, 21, 0, 'Action-adventure', 'Ukiyotei', 'Sony Imagesoft', '1992-07-17', 'A hook is a tool consisting of a length of material, typically metal, that contains a portion that is curved/bent back or has a deeply grooved indentation, which serves to grab, latch or in any way attach itself onto another object. The hook''s design allows traction forces to be relayed through the curved/indented portion to and from the proximal end of the hook, which is either a straight shaft or a ring for attachment to a thread, rope or chain, providing a reversible attachment between two objects.', 'https://media.retroachievements.org/Images/111494.png', 'https://media.retroachievements.org/Images/003163.png', 'https://media.retroachievements.org/Images/003164.png', 'https://media.retroachievements.org/Images/003165.png', 4),
  (176, 627, 'Dragon: The Bruce Lee Story', 'SNES/Super Famicom', 3, 1219, 1219, 1219, 38, 0, '2D Fighting', 'Virgin Interactive', 'Acclaim, Virgin Interactive', '1995-01-01', 'Dragon: The Bruce Lee Story is a 1993 American biographical drama film directed by Rob Cohen. The film stars Jason Scott Lee, with a supporting cast including Lauren Holly, Nancy Kwan, and Robert Wagner. The film follows the life of actor and martial artist Bruce Lee (Jason) from his relocation to the United States from Hong Kong to his career as a martial arts teacher, and then as a television and film actor. It also focuses on the relationship between Bruce and his wife Linda, and the racism to which Bruce was subjected.', 'https://media.retroachievements.org/Images/062623.png', 'https://media.retroachievements.org/Images/028543.png', 'https://media.retroachievements.org/Images/028541.png', 'https://media.retroachievements.org/Images/028542.png', 4),
  (177, 1392, 'Star Ocean', 'SNES/Super Famicom', 3, 1213, 1213, 1213, 67, 0, 'Action RPG', 'tri-Ace', 'Enix', '1996-07-19', 'Star Ocean is a franchise of science fantasy Action role-playing video games developed by the Japanese company tri-Ace and published by Square Enix.', 'https://media.retroachievements.org/Images/064813.png', 'https://media.retroachievements.org/Images/101305.png', 'https://media.retroachievements.org/Images/003573.png', 'https://media.retroachievements.org/Images/003575.png', 4),
  (178, 1424, 'Super Star Wars: The Empire Strikes Back', 'SNES/Super Famicom', 3, 1195, 1195, 1195, 46, 0, '2D Platforming, Action', 'LucasArts | Lucasfilm', 'JVC, THQ', '1993-06-01', 'Super Star Wars: The Empire Strikes Back, also known as Super Empire Strikes Back, is a 1993 action video game developed by LucasArts and Sculptured Software and published by JVC Musical Industries for the Super Nintendo Entertainment System. It is based on the 1980 film The Empire Strikes Back and is the sequel to Super Star Wars. The game was followed by a sequel, Super Star Wars: Return of the Jedi in 1994. Unlike its predecessor, Nintendo was not involved in its publishing. The game was re-released on the Wii''s Virtual Console in North America on August 24, 2009 and in the PAL regions on October 2, 2009, alongside the other games in the Super Star Wars series.', 'https://media.retroachievements.org/Images/061312.png', 'https://media.retroachievements.org/Images/045655.png', 'https://media.retroachievements.org/Images/006086.png', 'https://media.retroachievements.org/Images/006087.png', 4),
  (179, 1210, 'Super Bowling', 'SNES/Super Famicom', 3, 1186, 1186, 1186, 20, 0, 'Sports - Bowling', 'Athena, Technos Japan', 'Technos Japan', '1992-07-03', 'Super Bowling (スーパーボウリング) is a 1992 sports video game for the Super NES and the Nintendo 64. It was developed by KID and published by Athena, originally only for the SNES. It was later picked up by American Technōs and UFO Interactive and released for the N64 in 1999.', 'https://media.retroachievements.org/Images/066245.png', 'https://media.retroachievements.org/Images/005846.png', 'https://media.retroachievements.org/Images/005848.png', 'https://media.retroachievements.org/Images/005849.png', 4),
  (180, 1102, 'Pocky & Rocky 2', 'SNES/Super Famicom', 3, 1176, 1176, 1176, 85, 0, NULL, 'Natsume', 'Natsume', '1994-06-17', 'Pocky & Rocky 2, released in Japan as Kiki Kaikai: Tsukiyo Soushi , is a shoot ''em up video game developed and published by Natsume Co., Ltd. in Japan, published by Natsume Inc. in North America, and published in PAL regions by Ocean Software for the Super NES video game console. It is the sequel to Pocky & Rocky.', 'https://media.retroachievements.org/Images/037042.png', 'https://media.retroachievements.org/Images/006532.png', 'https://media.retroachievements.org/Images/006533.png', 'https://media.retroachievements.org/Images/006534.png', 4),
  (181, 429, 'Beethoven''s 2nd', 'SNES/Super Famicom', 3, 1169, 1169, 1169, 10, 0, '2D Platforming', 'Riedel Software Productions', 'Hi-Tech Expressions', '1993-12-01', 'The Symphony No. 2 in D major, Op. 36, is a symphony in four movements written by Ludwig van Beethoven between 1801 and 1802. The work is dedicated to Karl Alois, Prince Lichnowsky.', 'https://media.retroachievements.org/Images/052568.png', 'https://media.retroachievements.org/Images/017260.png', 'https://media.retroachievements.org/Images/017257.png', 'https://media.retroachievements.org/Images/017258.png', 4),
  (182, 8463, '~Hack~ Mega Man X3: Zero Project', 'SNES/Super Famicom', 3, 1168, 1168, 1168, 76, 0, 'Action / Platforming', 'Justin3009', 'Hack - Mega Man X3', '2012-01-31', 'Mega Man X is a series of action-platform games released by Capcom. It is a sub-series of the Mega Man franchise previously developed by the same group, with Keiji Inafune acting as one of the main staff members. The first game was released on 17 December 1993 in Japan on the Super Famicom and the following month on the Super NES in North America. Most of the sequels were ported to Microsoft Windows. The gameplay introduces new elements to the Mega Man franchise in the form of Mega Man''s successor X, including his new skills and power-ups in the form of armors while retaining the ability to decide which boss to fight first. The franchise is also known for its replay value, in which certain choices and optional content can influence both gameplay and storylines, allowing the player to experience alternate scenarios.', 'https://media.retroachievements.org/Images/056191.png', 'https://media.retroachievements.org/Images/016573.png', 'https://media.retroachievements.org/Images/008536.png', 'https://media.retroachievements.org/Images/008537.png', 4),
  (183, 2865, '~Hack~ A Plumber For All Seasons', 'SNES/Super Famicom', 3, 1165, 1165, 1165, 76, 0, '2D Platforming', 'WhiteYoshiEgg', 'Hack - Super Mario World', '2021-07-06', 'Super Mario Bros. is a 1985 platform game developed and published by Nintendo for the Nintendo Entertainment System (NES). Directed and produced by Shigeru Miyamoto, it is the successor to the 1983 arcade game Mario Bros. and the first game in the Super Mario series. Players control Mario, or his brother Luigi in the multiplayer mode, to traverse the Mushroom Kingdom to rescue Princess Toadstool from King Koopa. They traverse side-scrolling stages while avoiding hazards such as enemies and pits and collecting power-ups such as the Super Mushroom, Fire Flower, and Starman.', 'https://media.retroachievements.org/Images/047272.png', 'https://media.retroachievements.org/Images/051320.png', 'https://media.retroachievements.org/Images/045904.png', 'https://media.retroachievements.org/Images/045905.png', 4),
  (184, 1346, 'Yoshi''s Cookie', 'SNES/Super Famicom', 3, 1148, 1148, 1148, 77, 0, 'Tile Matching', 'TOSE', 'Bullet-Proof Software', '1993-06-01', 'Yoshi''s Cookie is a 1992 tile-matching puzzle video game developed by Tose and published by Nintendo for the NES and Game Boy platforms in 1992. A Super NES version was released the following year, developed and published by Bullet-Proof Software.', 'https://media.retroachievements.org/Images/075902.png', 'https://media.retroachievements.org/Images/007507.png', 'https://media.retroachievements.org/Images/046816.png', 'https://media.retroachievements.org/Images/046817.png', 4),
  (185, 3808, 'Super Off Road', 'SNES/Super Famicom', 3, 1147, 1147, 1147, 59, 0, 'Racing', 'Leland', 'Virgin Interactive', '1991-12-01', 'Ivan ''Ironman'' Stewart''s Super Off Road is a 1989 racing video game developed and published by Leland Corporation for arcades. It was designed and managed by John Morgan, who was also lead programmer, and endorsed by professional off-road racer Ivan Stewart. Virgin Games produced several home computer versions in 1990, with a version for the Nintendo Entertainment System released by Leland''s Tradewest subsidiary the same year. It was followed by versions for most major home consoles, including the Master System, Sega Genesis, and Super Nintendo Entertainment System. A port for the Atari Jaguar was announced but never released. Some ports lack the Ivan Stewart branding because of licensing issues, and are known simply as Super Off Road.', 'https://media.retroachievements.org/Images/109876.png', 'https://media.retroachievements.org/Images/032668.png', 'https://media.retroachievements.org/Images/032670.png', 'https://media.retroachievements.org/Images/032669.png', 4),
  (186, 6231, 'Dragon Quest III: Soshite Densetsu e...', 'SNES/Super Famicom', 3, 1143, 1143, 1143, 97, 0, 'Turn-Based RPG', 'Heartbeat', 'Enix', '1996-12-06', 'Dragon Quest III: The Seeds of Salvation, titled Dragon Warrior III when initially localized to North America, is a 1988 role-playing video game developed by Chunsoft and published by Enix. It is the third installment in the Dragon Quest series and was first released for the Family Computer (Famicom) in Japan and later for the Nintendo Entertainment System (NES) in North America. The game saw an enhanced remake for the Super Famicom in 1996 and the Game Boy Color in 2001, and a port to mobile phones and the Wii in 2009 and 2011. A version of the game for Android and iOS was released in Japan on September 25, 2014, and worldwide as Dragon Quest III: The Seeds of Salvation on December 4, 2014. It was the first time the game was given an official English subtitle. Later in 2021, another remake of the game titled Dragon Quest III HD-2D Remake, based on the HD-2D graphical style of Octopath Traveler (2018), was announced during the franchise''s 35th anniversary livestream. The remake was released on November 14th, 2024 for Nintendo Switch, PlayStation 5, Windows, and Xbox Series consoles.', 'https://media.retroachievements.org/Images/067893.png', 'https://media.retroachievements.org/Images/008405.png', 'https://media.retroachievements.org/Images/008395.png', 'https://media.retroachievements.org/Images/015363.png', 4),
  (187, 1353, 'Pinocchio', 'SNES/Super Famicom', 3, 1141, 1141, 1141, 37, 0, '2D Platforming', 'Virgin Interactive', 'Nintendo', '1996-11-01', 'Pinocchio is a fictional character and the protagonist of the children''s novel The Adventures of Pinocchio (1881) by Italian writer Carlo Collodi of Florence, Tuscany. Pinocchio was carved by a poor man named Geppetto in a Tuscan village. He is created as a wooden puppet, but he dreams of becoming a real boy. He is known for his long nose, which grows when he lies.', 'https://media.retroachievements.org/Images/062337.png', 'https://media.retroachievements.org/Images/008777.png', 'https://media.retroachievements.org/Images/027937.png', 'https://media.retroachievements.org/Images/027938.png', 4),
  (188, 968, 'The Jungle Book', 'SNES/Super Famicom', 3, 1125, 1125, 1125, 21, 0, '2D Platforming', 'Virgin Interactive', 'Virgin Interactive', '1994-07-15', 'The Jungle Book is an 1894 collection of stories by the English author Rudyard Kipling. Most of the characters are animals such as Shere Khan the tiger and Baloo the bear, though a principal character is the boy or man-cub Mowgli, who is raised in the jungle by wolves. Most stories are set in a forest in India; one place mentioned repeatedly is Seeonee (Seoni), in the central state of Madhya Pradesh.', 'https://media.retroachievements.org/Images/059503.png', 'https://media.retroachievements.org/Images/007096.png', 'https://media.retroachievements.org/Images/007094.png', 'https://media.retroachievements.org/Images/007095.png', 4),
  (189, 1213, 'Super Chase H.Q.', 'SNES/Super Famicom', 3, 1123, 1123, 1123, 28, 0, 'Racing', 'Taito', 'Taito', '1993-12-01', 'Super Chase H.Q. is a 1992 arcade racing game developed and published by Taito. It is the third release in the Chase H.Q. series, and the sequel to Special Criminal Investigation. After the initial release in Japanese arcades under the title Super Chase: Criminal Termination, it was re-released in North America in 1993 for the Super Nintendo.', 'https://media.retroachievements.org/Images/121621.png', 'https://media.retroachievements.org/Images/009726.png', 'https://media.retroachievements.org/Images/009730.png', 'https://media.retroachievements.org/Images/009731.png', 4),
  (190, 1354, 'Tiny Toon Adventures: Wacky Sports Challenge', 'SNES/Super Famicom', 3, 1123, 1123, 1123, 59, 0, 'Sports', 'Konami', 'Konami', '1994-09-30', 'Tiny Toon Adventures: Wacky Sports Challenge is a sports video game. The game was released in 1994 for the Super Nintendo Entertainment System and developed and published by Konami. It is based on the American children’s television series, Tiny Toon Adventures. It is one of the few SNES games to feature an SNES Multitap as a useable controller.', 'https://media.retroachievements.org/Images/073611.png', 'https://media.retroachievements.org/Images/002387.png', 'https://media.retroachievements.org/Images/002389.png', 'https://media.retroachievements.org/Images/002388.png', 4),
  (191, 1040, 'Mr. Do!', 'SNES/Super Famicom', 3, 1122, 1122, 1122, 20, 0, 'Maze Chase', 'C-Lab', 'Black Pearl', '1996-12-01', 'Mr. Do! is a 1982 maze video game developed by Universal. It is the first arcade video game to be released as a conversion kit for other cabinets; Taito published the conversion kit in Japan. The game was inspired by Namco''s Dig Dug, released earlier in 1982. Mr. Do! was a commercial success in Japan and North America, selling 30,000 arcade units in the US, and it was followed by several arcade sequels.', 'https://media.retroachievements.org/Images/119055.png', 'https://media.retroachievements.org/Images/009921.png', 'https://media.retroachievements.org/Images/009919.png', 'https://media.retroachievements.org/Images/009920.png', 4),
  (192, 1180, 'Venom and Spider-Man: Separation Anxiety', 'SNES/Super Famicom', 3, 1120, 1120, 1120, 50, 0, 'Beat ''em Up', 'Software Creations', 'Acclaim', '1995-11-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/122977.png', 'https://media.retroachievements.org/Images/008041.png', 'https://media.retroachievements.org/Images/010315.png', 'https://media.retroachievements.org/Images/010316.png', 4),
  (193, 3226, 'Mario is Missing!', 'SNES/Super Famicom', 3, 1115, 1115, 1115, 36, 0, 'Educational', 'Software Toolworks', 'Mindscape, Software Toolworks', '1993-06-01', 'Mario Is Missing! is a 1993 educational game developed and published by The Software Toolworks for MS-DOS, Nintendo Entertainment System, and Super Nintendo Entertainment System, later released on Macintosh in 1994. The player controls Luigi, who must travel around the world to find and return stolen treasures as part of a quest to locate his brother, Mario, who has been captured by Bowser. Mario Is Missing!, part of a series of educational Mario games, was Luigi''s second starring role in a video game, following the 1990 Game Watch game Luigi''s Hammer Toss and preceding the 2001 GameCube game Luigi''s Mansion.', 'https://media.retroachievements.org/Images/117694.png', 'https://media.retroachievements.org/Images/070018.png', 'https://media.retroachievements.org/Images/004236.png', 'https://media.retroachievements.org/Images/004237.png', 4),
  (194, 3363, 'Picross NP Vol. 2', 'SNES/Super Famicom', 3, 1115, 1115, 1115, 27, 0, 'Nonogram', 'Jupiter', 'Nintendo', '1999-06-01', 'The Super Nintendo Entertainment System has a library of 1,749 official releases, of which 717 were released in North America plus 4 championship cartridges, 532 in Europe, 1,440 in Japan, 231 on Satellaview, and 13 on SuFami Turbo. 296 releases are common to all regions, 147 were released in Japan and the US only, 165 in Europe and the US, and 27 in Japan and Europe. There are 977 Japanese exclusives, 111 US exclusives, and 35 European exclusives. The Super NES was released in North America on August 23, 1991, with its launch titles being Super Mario World, F-Zero, Pilotwings, Gradius III, and SimCity. Despite the console''s relatively late start, and the fierce competition it faced in North America and Europe from Sega''s Genesis/Mega Drive console, it was the best-selling console of its era.', 'https://media.retroachievements.org/Images/024812.png', 'https://media.retroachievements.org/Images/024929.png', 'https://media.retroachievements.org/Images/008203.png', 'https://media.retroachievements.org/Images/008211.png', 4),
  (195, 3166, 'Krusty''s Super Fun House', 'SNES/Super Famicom', 3, 1113, 1113, 1113, 82, 0, NULL, 'Audiogenic', 'Acclaim', '1992-06-01', 'Krusty''s Fun House, also known as Krusty''s Super Fun House is a 1992 puzzle video game based on the animated sitcom The Simpsons. It was developed by Audiogenic and published by Acclaim Entertainment for the Nintendo Entertainment System (NES), Super Nintendo Entertainment System (SNES), Sega Genesis, Master System, Game Gear, and Game Boy; versions for the Amiga and MS-DOS computers were released by Virgin Games. In the game, players control Krusty the Clown as they attempt to exterminate all rats in the various levels, using objects to create a path for the rats towards the machine.', 'https://media.retroachievements.org/Images/064561.png', 'https://media.retroachievements.org/Images/057349.png', 'https://media.retroachievements.org/Images/008794.png', 'https://media.retroachievements.org/Images/008835.png', 4),
  (196, 1197, 'Super Adventure Island II', 'SNES/Super Famicom', 3, 1106, 1106, 1106, 49, 0, '2D Platforming', 'Make Software', 'Hudson Soft', '1995-01-03', 'Super Adventure Island II  is a platform video game released by Hudson Soft for the Super NES in 1994 in North America, with subsequent releases in Japan and Europe following in 1995. Unlike most of the previous games, it is a platformer with action-adventure elements that encourages exploration, similar to the later Wonder Boy games.', 'https://media.retroachievements.org/Images/028586.png', 'https://media.retroachievements.org/Images/007909.png', 'https://media.retroachievements.org/Images/008353.png', 'https://media.retroachievements.org/Images/008354.png', 4),
  (197, 911, 'Firepower 2000', 'SNES/Super Famicom', 3, 1102, 1102, 1102, 34, 0, 'Shoot ''em Up', 'SCi Games | Sales Curve Interactive', 'Sunsoft', '1992-01-01', 'Super SWIV is a top-down shoot ''em up released for the Super Nintendo Entertainment System in 1992. It was released as Mega SWIV on the Mega Drive in 1995. It is the sequel to the 1991 game SWIV. It was followed by SWIV 3D in 1996.', 'https://media.retroachievements.org/Images/063158.png', 'https://media.retroachievements.org/Images/005136.png', 'https://media.retroachievements.org/Images/005133.png', 'https://media.retroachievements.org/Images/005134.png', 4),
  (198, 8249, '~Hack~ Donkey Kong Country: Competition Edition [10 Minutes]', 'SNES/Super Famicom', 3, 1097, 1097, 1097, 38, 0, '2D Platforming', 'Hack', 'Hack - Donkey Kong Country', '1994-11-21', 'Donkey Kong is a video game series and media franchise created by the Japanese game designer Shigeru Miyamoto for Nintendo. It follows the adventures of Donkey Kong, a large, powerful gorilla, and other members of the Kong family of apes. Donkey Kong games include the original arcade game trilogy by Nintendo R&D1; the Donkey Kong Country series by Rare and Retro Studios; and the Mario vs. Donkey Kong series by Nintendo Software Technology. Various studios have developed spin-offs in genres such as edutainment, puzzle, racing, and rhythm. The franchise also incorporates animation, printed media, theme parks, and merchandise.', 'https://media.retroachievements.org/Images/116327.png', 'https://media.retroachievements.org/Images/060828.png', 'https://media.retroachievements.org/Images/024442.png', 'https://media.retroachievements.org/Images/009063.png', 4),
  (199, 1287, 'The Twisted Tales of Spike McFang', 'SNES/Super Famicom', 3, 1082, 1082, 1082, 46, 0, 'Action RPG', 'Red Company', 'Naxat Soft', '1994-06-01', 'The Twisted Tales of Spike McFang  is an action role-playing video game developed by Red Company for the Super Nintendo Entertainment System. It was released by Naxat Soft in Japan and by Bullet-Proof Software in North America. The game is the sequel to the TurboGrafx-16 game Makai Prince Dorabotchan, which was only released in Japan. The characters also appeared in the Japanese Super Naxat Open golf game for Super Famicom.', 'https://media.retroachievements.org/Images/026971.png', 'https://media.retroachievements.org/Images/005144.png', 'https://media.retroachievements.org/Images/005145.png', 'https://media.retroachievements.org/Images/005146.png', 4),
  (200, 3206, 'Magic Knight Rayearth', 'SNES/Super Famicom', 3, 1072, 1072, 1072, 17, 0, 'Turn-Based RPG', 'Pandora Box', 'Tomy', '1995-09-29', 'Magic Knight Rayearth  is a Japanese manga series written and illustrated by Clamp. Appearing as a serial in the manga magazine Nakayoshi from the November 1993 issue to the February 1995 issue, the chapters of Magic Knight Rayearth were collected into three bound volumes by Kodansha. They were published from July 1994 to March 1995. A sequel was serialized in the same manga magazine from the March 1995 issue to the April 1996 issue. It was published by Kodansha in three bound volumes from July 1995 to April 1996.', 'https://media.retroachievements.org/Images/112420.png', 'https://media.retroachievements.org/Images/112634.png', 'https://media.retroachievements.org/Images/053431.png', 'https://media.retroachievements.org/Images/053430.png', 4);
